// Р¤СѓРЅРєС†РёСЏ РґР»СЏ РѕС‚РєР»СЋС‡РµРЅРёСЏ Р°РЅРёРјР°С†РёР№ РєР°СЂС‚РѕС‡РµРє РјРѕРґРѕРІ
function disableModCardAnimations() {
    // console.log('рџљ« РћС‚РєР»СЋС‡РµРЅРёРµ Р°РЅРёРјР°С†РёР№ РєР°СЂС‚РѕС‡РµРє РјРѕРґРѕРІ...');
    
    // РџСЂРѕРІРµСЂСЏРµРј, СѓР¶Рµ Р»Рё РґРѕР±Р°РІР»РµРЅС‹ СЃС‚РёР»Рё
    if (document.getElementById('disable-mod-animations')) {
        // console.log('рџ“Њ РЎС‚РёР»Рё РґР»СЏ РѕС‚РєР»СЋС‡РµРЅРёСЏ Р°РЅРёРјР°С†РёР№ СѓР¶Рµ РґРѕР±Р°РІР»РµРЅС‹');
        return;
    }
    
    // РЎРѕР·РґР°РµРј Рё РґРѕР±Р°РІР»СЏРµРј CSS СЃС‚РёР»Рё
    const style = document.createElement('style');
    style.id = 'disable-mod-animations';
    style.textContent = `
        /* РћС‚РєР»СЋС‡Р°РµРј РІСЃРµ Р°РЅРёРјР°С†РёРё РґР»СЏ РєР°СЂС‚РѕС‡РµРє РјРѕРґРѕРІ */
        .mod-card,
        .mod-card *,
        .mod-card *::before,
        .mod-card *::after {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
        
        /* РћС‚РєР»СЋС‡Р°РµРј Р°РЅРёРјР°С†РёРё РїРѕСЏРІР»РµРЅРёСЏ РґР»СЏ РєРѕРЅС‚РµР№РЅРµСЂР° РјРѕРґРѕРІ */
        #modsContainer,
        #modsContainer *,
        .mods-container,
        .mods-container * {
            animation: none !important;
            transition: none !important;
        }
        
        /* РћС‚РєР»СЋС‡Р°РµРј Р°РЅРёРјР°С†РёРё РґР»СЏ РёР·РѕР±СЂР°Р¶РµРЅРёР№ РјРѕРґРѕРІ */
        .mod-card img,
        .mod-card-image-container img {
            animation: none !important;
            transition: none !important;
        }
        
        /* РћС‚РєР»СЋС‡Р°РµРј Р°РЅРёРјР°С†РёРё РґР»СЏ РєРЅРѕРїРѕРє РІ РєР°СЂС‚РѕС‡РєР°С… */
        .mod-card button,
        .mod-card .download-btn,
        .mod-card .details-btn {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
        
        /* РћС‚РєР»СЋС‡Р°РµРј hover СЌС„С„РµРєС‚С‹ РґР»СЏ РєР°СЂС‚РѕС‡РµРє */
        .mod-card:hover,
        .mod-card *:hover {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
        
        /* Р“Р»РѕР±Р°Р»СЊРЅРѕРµ РѕС‚РєР»СЋС‡РµРЅРёРµ Р°РЅРёРјР°С†РёР№ РґР»СЏ РІСЃРµС… СЌР»РµРјРµРЅС‚РѕРІ РІРЅСѓС‚СЂРё РєР°СЂС‚РѕС‡РµРє */
        .mod-card * {
            animation-duration: 0s !important;
            transition-duration: 0s !important;
            animation-delay: 0s !important;
            transition-delay: 0s !important;
        }
        
        /* РџСЂРёРЅСѓРґРёС‚РµР»СЊРЅРѕРµ РѕС‚РєР»СЋС‡РµРЅРёРµ transform РґР»СЏ РєР°СЂС‚РѕС‡РµРє */
        .mod-card {
            transform: none !important;
            transform-origin: initial !important;
        }
        
        /* РћС‚РєР»СЋС‡Р°РµРј Р°РЅРёРјР°С†РёРё РґР»СЏ VIP РєР°СЂС‚РѕС‡РµРє */
        .mod-card.vip-mod,
        .mod-card.vip-mod * {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
    `;
    
    document.head.appendChild(style);
    console.log('вњ… РђРЅРёРјР°С†РёРё РєР°СЂС‚РѕС‡РµРє РјРѕРґРѕРІ РѕС‚РєР»СЋС‡РµРЅС‹');
}

// Р¤СѓРЅРєС†РёСЏ РґР»СЏ РІРєР»СЋС‡РµРЅРёСЏ Р°РЅРёРјР°С†РёР№ РѕР±СЂР°С‚РЅРѕ (РµСЃР»Рё РЅСѓР¶РЅРѕ)
function enableModCardAnimations() {
    const style = document.getElementById('disable-mod-animations');
    if (style) {
        style.remove();
        console.log('вњ… РђРЅРёРјР°С†РёРё РєР°СЂС‚РѕС‡РµРє РјРѕРґРѕРІ РІРєР»СЋС‡РµРЅС‹');
    }
}

// Р”РѕР±Р°РІР»СЏРµРј РІ РіР»РѕР±Р°Р»СЊРЅСѓСЋ РѕР±Р»Р°СЃС‚СЊ РґР»СЏ РґРѕСЃС‚СѓРїР° РёР· РєРѕРЅСЃРѕР»Рё
