// Р’С‹Р·С‹РІР°РµРј С„СѓРЅРєС†РёСЋ СЃСЂР°Р·Сѓ РїСЂРё Р·Р°РіСЂСѓР·РєРµ
disableModCardAnimations();

// console.log('рџљ« Р—Р°РіСЂСѓР¶РµРЅ РјРѕРґСѓР»СЊ РѕС‚РєР»СЋС‡РµРЅРёСЏ Р°РЅРёРјР°С†РёР№ РєР°СЂС‚РѕС‡РµРє РјРѕРґРѕРІ');

// Р“Р»РѕР±Р°Р»СЊРЅС‹Рµ РїРµСЂРµРјРµРЅРЅС‹Рµ, РєРѕРЅСЃС‚Р°РЅС‚С‹ Рё С„СѓРЅРєС†РёРё РґР»СЏ РјРѕРґР°Р»СЊРЅС‹С… РѕРєРѕРЅ С‚РµРїРµСЂСЊ Р·Р°РіСЂСѓР¶Р°СЋС‚СЃСЏ РёР· js/core.js Рё js/ui-modals.js
// РґР»СЏ РїСЂРµРґРѕС‚РІСЂР°С‰РµРЅРёСЏ РєРѕРЅС„Р»РёРєС‚РѕРІ Рё С†РµРЅС‚СЂР°Р»РёР·Р°С†РёРё СѓРїСЂР°РІР»РµРЅРёСЏ.

// Р’СЂРµРјРµРЅРЅРѕ РѕР±СЉСЏРІР»СЏРµРј Р·РґРµСЃСЊ РґР»СЏ РёСЃРїСЂР°РІР»РµРЅРёСЏ РѕС€РёР±РѕРє Р·Р°РіСЂСѓР·РєРё
if (typeof DEBUG_MODE === 'undefined') window.DEBUG_MODE = false; // РћС‚РєР»СЋС‡Р°РµРј Р»РѕРіРё РґР»СЏ РїСЂРѕРёР·РІРѕРґРёС‚РµР»СЊРЅРѕСЃС‚Рё

// Р“Р»РѕР±Р°Р»СЊРЅС‹Рµ РїРµСЂРµРјРµРЅРЅС‹Рµ
let supabaseClient;
let currentMod = null;
let currentGameVersion = 'fs25';
let currentCategory = 'Р’СЃРµ';
let isVipMode = false;
