// РљРѕРЅСЃС‚Р°РЅС‚Р° РґР»СЏ РїРµСЂРµРґР°С‡Рё РїСЂР°РІ РІР»Р°РґРµР»СЊС†Р° (РёР·РјРµРЅРёС‚Рµ РЅР° СЃРІРѕР№ СѓРЅРёРєР°Р»СЊРЅС‹Р№ РїР°СЂРѕР»СЊ)
const OWNER_TRANSFER_PASSWORD = 'KerosOwnerTransfer2025!';

// РЎРёСЃС‚РµРјР° Р±РµРіСѓС‰РµР№ СЃС‚СЂРѕРєРё СѓРІРµРґРѕРјР»РµРЅРёР№
class NotificationTicker {
    constructor() {
        this.ticker = document.getElementById('notification-ticker');
        this.content = document.getElementById('ticker-content');
        this.messages = [];
        this.currentIndex = 0;
        this.isVisible = false;
        console.log('рџЏѓвЂЌв™‚пёЏ NotificationTicker РёРЅРёС†РёР°Р»РёР·РёСЂРѕРІР°РЅ:', { ticker: !!this.ticker, content: !!this.content });
    }

    // РџРѕРєР°Р·Р°С‚СЊ Р±РµРіСѓС‰СѓСЋ СЃС‚СЂРѕРєСѓ
    show(type = 'info') {
        if (!this.ticker) return;
        
        this.ticker.style.display = 'block';
        this.ticker.className = type;
        this.isVisible = true;
        // console.log('рџ“ў Р‘РµРіСѓС‰Р°СЏ СЃС‚СЂРѕРєР° РїРѕРєР°Р·Р°РЅР° СЃ С‚РёРїРѕРј:', type);
    }

    // РЎРєСЂС‹С‚СЊ Р±РµРіСѓС‰СѓСЋ СЃС‚СЂРѕРєСѓ
    hide() {
        if (!this.ticker) return;
        
        this.ticker.style.display = 'none';
        this.isVisible = false;
        // console.log('рџ”‡ Р‘РµРіСѓС‰Р°СЏ СЃС‚СЂРѕРєР° СЃРєСЂС‹С‚Р°');
    }

    // Р”РѕР±Р°РІРёС‚СЊ СЃРѕРѕР±С‰РµРЅРёРµ Рѕ РїСЂРµРґСѓРїСЂРµР¶РґРµРЅРёРё
    addWarningMessage(username, reason, moderatorName) {
        // РЈР»СѓС‡С€Р°РµРј РѕС‚РѕР±СЂР°Р¶РµРЅРёРµ РёРјРµРЅРё РјРѕРґРµСЂР°С‚РѕСЂР°
        const displayName = moderatorName === 'РђРґРјРёРЅРёСЃС‚СЂР°С†РёСЏ' ? 'РђРґРјРёРЅРёСЃС‚СЂР°С†РёСЏ СЃР°Р№С‚Р°' : moderatorName;
        const message = `вљ пёЏ РџРѕР»СЊР·РѕРІР°С‚РµР»СЋ ${username} РІС‹РЅРµСЃРµРЅРѕ РїСЂРµРґСѓРїСЂРµР¶РґРµРЅРёРµ: ${reason} (${displayName})`;
        this.addMessage(message, 'warning');
    }

    // Р”РѕР±Р°РІРёС‚СЊ СЃРѕРѕР±С‰РµРЅРёРµ Рѕ Р±Р»РѕРєРёСЂРѕРІРєРµ
    addBanMessage(username, reason, moderatorName) {
        // РЈР»СѓС‡С€Р°РµРј РѕС‚РѕР±СЂР°Р¶РµРЅРёРµ РёРјРµРЅРё РјРѕРґРµСЂР°С‚РѕСЂР°
        const displayName = moderatorName === 'РђРґРјРёРЅРёСЃС‚СЂР°С†РёСЏ' ? 'РђРґРјРёРЅРёСЃС‚СЂР°С†РёСЏ СЃР°Р№С‚Р°' : moderatorName;
        const message = `рџљ« РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ ${username} Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ: ${reason} (${displayName})`;
        this.addMessage(message, 'warning');
    }

    // Р”РѕР±Р°РІРёС‚СЊ РёРЅС„РѕСЂРјР°С†РёРѕРЅРЅРѕРµ СЃРѕРѕР±С‰РµРЅРёРµ
    addInfoMessage(message) {
        this.addMessage(`рџ“ў ${message}`, 'info');
    }

    // Р”РѕР±Р°РІРёС‚СЊ СЂРµРєР»Р°РјРЅРѕРµ СЃРѕРѕР±С‰РµРЅРёРµ
    addAdMessage(message) {
        this.addMessage(`рџ’Ћ ${message}`, 'success');
    }

    // Р”РѕР±Р°РІРёС‚СЊ РѕР±С‰РµРµ СЃРѕРѕР±С‰РµРЅРёРµ
    addMessage(message, type = 'info') {
        this.messages.push({ text: message, type, timestamp: Date.now() });
        
        // РћРіСЂР°РЅРёС‡РёРІР°РµРј РєРѕР»РёС‡РµСЃС‚РІРѕ СЃРѕРѕР±С‰РµРЅРёР№
        if (this.messages.length > 10) {
            this.messages.shift();
        }

        this.updateTicker();
        this.show(type);
        // console.log('рџ“Ё Р”РѕР±Р°РІР»РµРЅРѕ СЃРѕРѕР±С‰РµРЅРёРµ РІ Р±РµРіСѓС‰СѓСЋ СЃС‚СЂРѕРєСѓ:', message);
    }

    // РћР±РЅРѕРІРёС‚СЊ СЃРѕРґРµСЂР¶РёРјРѕРµ Р±РµРіСѓС‰РµР№ СЃС‚СЂРѕРєРё
    updateTicker() {
        if (!this.content) return;

        if (this.messages.length === 0) {
            this.content.textContent = 'рџ“ў Р”РѕР±СЂРѕ РїРѕР¶Р°Р»РѕРІР°С‚СЊ РЅР° KEROSMODS.RU! рџљњ Р›СѓС‡С€РёРµ РјРѕРґС‹ РґР»СЏ Farming Simulator!';
            return;
        }

        // РћР±СЉРµРґРёРЅСЏРµРј РІСЃРµ СЃРѕРѕР±С‰РµРЅРёСЏ С‡РµСЂРµР· СЂР°Р·РґРµР»РёС‚РµР»СЊ
        const messagesText = this.messages.map(msg => msg.text).join(' вЂў ');
        this.content.textContent = messagesText;
        // console.log('рџ”„ Р‘РµРіСѓС‰Р°СЏ СЃС‚СЂРѕРєР° РѕР±РЅРѕРІР»РµРЅР°:', messagesText);
    }

    // РћС‡РёСЃС‚РёС‚СЊ РІСЃРµ СЃРѕРѕР±С‰РµРЅРёСЏ
    clear() {
        this.messages = [];
        this.updateTicker();
        this.hide();
    }

    // РћС‡РёСЃС‚РёС‚СЊ СЃРѕРѕР±С‰РµРЅРёСЏ (Р±РµР· СЃРєСЂС‹С‚РёСЏ)
    clearMessages() {
        this.messages = [];
        this.updateTicker();
        console.log('рџ§№ РЎРѕРѕР±С‰РµРЅРёСЏ РІ Р±РµРіСѓС‰РµР№ СЃС‚СЂРѕРєРµ РѕС‡РёС‰РµРЅС‹');
    }
}

// РЎРѕР·РґР°РµРј РіР»РѕР±Р°Р»СЊРЅС‹Р№ СЌРєР·РµРјРїР»СЏСЂ РџРћРЎР›Р• Р·Р°РіСЂСѓР·РєРё DOM
