function initNotificationTicker() {
    console.log('рџЏѓвЂЌв™‚пёЏ РџРѕРїС‹С‚РєР° РёРЅРёС†РёР°Р»РёР·Р°С†РёРё NotificationTicker...');
    
    if (!window.notificationTicker) {
        window.notificationTicker = new NotificationTicker();
        console.log('вњ… NotificationTicker СЃРѕР·РґР°РЅ Рё РіРѕС‚РѕРІ Рє СЂР°Р±РѕС‚Рµ');
        
        // РќРµ РґРѕР±Р°РІР»СЏРµРј РЅР°С‡Р°Р»СЊРЅС‹Рµ СЃРѕРѕР±С‰РµРЅРёСЏ - Р¶РґРµРј РїРµСЂСЃРѕРЅР°Р»СЊРЅС‹Рµ СѓРІРµРґРѕРјР»РµРЅРёСЏ
        console.log('рџ“ў РћР¶РёРґР°РµРј РїРµСЂСЃРѕРЅР°Р»СЊРЅС‹Рµ СѓРІРµРґРѕРјР»РµРЅРёСЏ...');
        
    } else {
        console.log('вљ пёЏ NotificationTicker СѓР¶Рµ СЃСѓС‰РµСЃС‚РІСѓРµС‚');
    }
}

// Р“Р»РѕР±Р°Р»СЊРЅР°СЏ С„СѓРЅРєС†РёСЏ getCurrentUser РґР»СЏ РёСЃРїСЂР°РІР»РµРЅРёСЏ РѕС€РёР±РєРё Р°СѓС‚РµРЅС‚РёС„РёРєР°С†РёРё
function getCurrentUser() {
    console.log('рџ”Ќ [GET_CURRENT_USER] РќР°С‡Р°Р»Рѕ РїСЂРѕРІРµСЂРєРё Р°СѓС‚РµРЅС‚РёС„РёРєР°С†РёРё');
    console.log('рџ”Ќ [GET_CURRENT_USER] window.authManager:', window.authManager);
    console.log('рџ”Ќ [GET_CURRENT_USER] window.supabase:', window.supabase);
    console.log('рџ”Ќ [GET_CURRENT_USER] supabase.auth:', window.supabase?.auth);
    console.log('рџ”Ќ [GET_CURRENT_USER] supabase.auth.currentUser:', window.supabase?.auth?.currentUser);
    
    // РџСЂРѕРІРµСЂСЏРµРј СЃРµСЃСЃРёСЋ Supabase
    if (window.supabase && window.supabase.auth) {
        console.log('рџ”Ќ [GET_CURRENT_USER] РџСЂРѕРІРµСЂСЏРµРј СЃРµСЃСЃРёСЋ Supabase...');
        window.supabase.auth.getSession().then(({ data: { session }, error }) => {
            console.log('рџ”Ќ [GET_CURRENT_USER] РЎРµСЃСЃРёСЏ Supabase:', session);
            console.log('рџ”Ќ [GET_CURRENT_USER] РћС€РёР±РєР° СЃРµСЃСЃРёРё:', error);
            if (session) {
                console.log('рџ”Ќ [GET_CURRENT_USER] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РІ СЃРµСЃСЃРёРё:', session.user);
                // РЈР±СЂР°Р»Рё РІСЃРїР»С‹РІР°СЋС‰РµРµ СѓРІРµРґРѕРјР»РµРЅРёРµ
            } else {
                console.log('рџ”Ќ [GET_CURRENT_USER] РЎРµСЃСЃРёСЏ РЅРµ РЅР°Р№РґРµРЅР°');
                // РЈР±СЂР°Р»Рё РІСЃРїР»С‹РІР°СЋС‰РµРµ СѓРІРµРґРѕРјР»РµРЅРёРµ
            }
        });
    }
    
    if (window.authManager && typeof window.authManager.getCurrentUser === 'function') {
        console.log('рџ”Ќ [GET_CURRENT_USER] РСЃРїРѕР»СЊР·СѓРµРј authManager.getCurrentUser()');
        const user = window.authManager.getCurrentUser();
        console.log('рџ”Ќ [GET_CURRENT_USER] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РёР· authManager:', user);
        // РЈР±СЂР°Р»Рё РІСЃРїР»С‹РІР°СЋС‰РµРµ СѓРІРµРґРѕРјР»РµРЅРёРµ
        return user;
    }
    // РђР»СЊС‚РµСЂРЅР°С‚РёРІРЅС‹Р№ СЃРїРѕСЃРѕР± С‡РµСЂРµР· supabase auth
    if (window.supabase && window.supabase.auth && window.supabase.auth.currentUser) {
        console.log('рџ”Ќ [GET_CURRENT_USER] РСЃРїРѕР»СЊР·СѓРµРј supabase.auth.currentUser');
        const user = window.supabase.auth.currentUser;
        console.log('рџ”Ќ [GET_CURRENT_USER] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РёР· supabase:', user);
        // РЈР±СЂР°Р»Рё РІСЃРїР»С‹РІР°СЋС‰РµРµ СѓРІРµРґРѕРјР»РµРЅРёРµ
        return user;
    }
    console.log('рџ”Ќ [GET_CURRENT_USER] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ РЅР°Р№РґРµРЅ, РІРѕР·РІСЂР°С‰Р°РµРј null');
    // РЈР±СЂР°Р»Рё РІСЃРїР»С‹РІР°СЋС‰РµРµ СѓРІРµРґРѕРјР»РµРЅРёРµ
    return null;
}

