// РџРµСЂРµРѕРїСЂРµРґРµР»СЏРµРј console.log РґР»СЏ РѕС‚РєР»СЋС‡РµРЅРёСЏ Р»РѕРіРѕРІ
if (false) { // РџСЂРёРЅСѓРґРёС‚РµР»СЊРЅРѕ РѕС‚РєР»СЋС‡Р°РµРј РѕС‚РєР»СЋС‡РµРЅРёРµ Р»РѕРіРѕРІ
    const originalConsoleLog = console.log;
    const originalConsoleError = console.error;
    const originalConsoleWarn = console.warn;
    
    console.log = function(...args) {
        // РќРµ РІС‹РІРѕРґРёРј РЅРёС‡РµРіРѕ РµСЃР»Рё DEBUG_MODE РѕС‚РєР»СЋС‡РµРЅ
    };
    
    console.error = function(...args) {
        // РЎРѕС…СЂР°РЅСЏРµРј С‚РѕР»СЊРєРѕ РєСЂРёС‚РёС‡РµСЃРєРёРµ РѕС€РёР±РєРё
        if (args[0] && args[0].toString().includes('вќЊ')) {
            originalConsoleError.apply(console, args);
        }
    };
    
    console.warn = function(...args) {
        // РќРµ РІС‹РІРѕРґРёРј РїСЂРµРґСѓРїСЂРµР¶РґРµРЅРёСЏ
    };
}

// РСЃРїРѕР»СЊР·СѓРµРј var РІРјРµСЃС‚Рѕ const/let С‡С‚РѕР±С‹ РёР·Р±РµР¶Р°С‚СЊ TDZ РїСЂРѕР±Р»РµРј
var isAdminPanelOpening = false; // Р¤Р»Р°Рі РїСЂРµРґРѕС‚РІСЂР°С‰РµРЅРёСЏ РїРѕРІС‚РѕСЂРЅС‹С… РѕС‚РєСЂС‹С‚РёР№
var adminPanelState = 0; // 0 = РєРѕРјРїР°РєС‚РЅР°СЏ, 1 = РјРёРЅРё
var adminNavHistory = []; // РСЃС‚РѕСЂРёСЏ РЅР°РІРёРіР°С†РёРё РІ Р°РґРјРёРЅ-РїР°РЅРµР»Рё

// РРµСЂР°СЂС…РёСЏ СЂРѕР»РµР№ РґР»СЏ СѓРїСЂР°РІР»РµРЅРёСЏ РїСЂР°РІР°РјРё
var ROLE_HIERARCHY = {
    'owner': 7,
    'admin_senior': 6,
    'admin': 5,
    'moderator_senior': 4,
    'moderator': 3,
    'vip': 2,
    'user': 1
};

// Р¤СѓРЅРєС†РёРё РґР»СЏ РїСЂРѕРІРµСЂРєРё РёРЅРґРёРєР°С‚РѕСЂРѕРІ РїСЂРµРґСѓРїСЂРµР¶РґРµРЅРёР№ Рё Р±Р»РѕРєРёСЂРѕРІРѕРє
async function checkWarningsAndBansIndicators() {
    try {
        if (!window.supabase) return;

        // РџСЂРѕРІРµСЂСЏРµРј РїСЂРµРґСѓРїСЂРµР¶РґРµРЅРёСЏ
        let warnings = [];
        let warningsError = null;
        try {
            const currentUser = getCurrentUser();
            if (currentUser) {
                // РџРѕР»СѓС‡Р°РµРј РІСЃРµ РїСЂРµРґСѓРїСЂРµР¶РґРµРЅРёСЏ Рё С„РёР»СЊС‚СЂСѓРµРј РЅР° РєР»РёРµРЅС‚Рµ
                const { data: allWarnings, error: fetchError } = await window.supabase
                    .from('user_warnings')
                    .select('id, expires_at, user_id')
                    .limit(100);

                if (!fetchError && allWarnings) {
                    // Р¤РёР»СЊС‚СЂСѓРµРј РїРѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЋ Рё СЃС‚Р°С‚СѓСЃСѓ РЅР° РєР»РёРµРЅС‚Рµ
                    warnings = allWarnings.filter(w => 
                        w.user_id === currentUser.id &&
                        (w.expires_at === null || new Date(w.expires_at) > new Date())
                    );
                }
                warningsError = fetchError;
            }
        } catch (e) {
            console.warn('РћС€РёР±РєР° РїСЂРё РїСЂРѕРІРµСЂРєРµ РїСЂРµРґСѓРїСЂРµР¶РґРµРЅРёР№:', e);
            warningsError = e;
        }

        if (!warningsError && warnings && warnings.length > 0) {
            const indicator = document.getElementById('warnings-indicator');
            if (indicator) {
                indicator.style.display = 'inline';
                indicator.style.animation = 'blink 1s infinite';
            }
        }

        // РџСЂРѕРІРµСЂСЏРµРј Р±Р»РѕРєРёСЂРѕРІРєРё
        let bans = [];
        let bansError = null;
        try {
            const currentUser = getCurrentUser();
            if (currentUser) {
                // РџРѕР»СѓС‡Р°РµРј РІСЃРµ Р±Р»РѕРєРёСЂРѕРІРєРё Рё С„РёР»СЊС‚СЂСѓРµРј РЅР° РєР»РёРµРЅС‚Рµ
                const { data: allBans, error: fetchError } = await window.supabase
                    .from('comment_bans')
                    .select('id, ends_at, user_id')
                    .limit(100);

                if (!fetchError && allBans) {
                    // Р¤РёР»СЊС‚СЂСѓРµРј РїРѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЋ Рё СЃС‚Р°С‚СѓСЃСѓ РЅР° РєР»РёРµРЅС‚Рµ
                    bans = allBans.filter(b => 
                        b.user_id === currentUser.id &&
                        (b.ends_at === null || new Date(b.ends_at) > new Date())
                    );
                }
                bansError = fetchError;
            }
        } catch (e) {
            console.warn('РћС€РёР±РєР° РїСЂРё РїСЂРѕРІРµСЂРєРµ Р±Р»РѕРєРёСЂРѕРІРѕРє:', e);
            bansError = e;
        }

        if (!bansError && bans && bans.length > 0) {
            const indicator = document.getElementById('bans-indicator');
            if (indicator) {
                indicator.style.display = 'inline';
                indicator.style.animation = 'blink 1s infinite';
            }
        }
    } catch (error) {
        console.log('РћС€РёР±РєР° РїСЂРѕРІРµСЂРєРё РёРЅРґРёРєР°С‚РѕСЂРѕРІ:', error);
    }
}

// Р”РѕР±Р°РІР»СЏРµРј CSS Р°РЅРёРјР°С†РёСЋ РґР»СЏ РјРёРіР°РЅРёСЏ
if (!document.querySelector('#blink-animation-style')) {
    const style = document.createElement('style');
    style.id = 'blink-animation-style';
    style.textContent = `
        @keyframes blink {
            0%, 50% { opacity: 1; }
            25%, 75% { opacity: 0.3; }
        }
    `;
    document.head.appendChild(style);
}

