        'baling': 'РўСЋРєРѕРІРєР°',
        'plows': 'РџР»СѓРіРё',
        'cultivators': 'РљСѓР»СЊС‚РёРІР°С‚РѕСЂС‹',
        'mowers': 'РљРѕСЃРёР»РєРё',
        'sprayers': 'РћРїСЂС‹СЃРєРёРІР°С‚РµР»Рё',
        'manure_spreaders': 'РќР°РІРѕР·РѕСЂР°Р·Р±СЂР°СЃС‹РІР°С‚РµР»Рё',
        'farm_implements': 'РЎРµР»СЊС…РѕР· РёРЅРІРµРЅС‚Р°СЂСЊ',
