        'objects': 'РћР±СЉРµРєС‚С‹',
        'buildings': 'Р—РґР°РЅРёСЏ',
        'scripting': 'РЎРєСЂРёРїС‚РёРЅРі',
        'russian_mods': 'Р СѓСЃСЃРєРёРµ РјРѕРґС‹',
        'russian': 'Р СѓСЃСЃРєРёРµ РјРѕРґС‹',
        'other_modifications': 'Р”СЂСѓРіРёРµ РјРѕРґРёС„РёРєР°С†РёРё',
        'other': 'РџСЂРѕС‡РµРµ',
        
