// РџРѕР»СѓС‡РµРЅРёРµ РїРѕР»РЅРѕРіРѕ РёРјРµРЅРё РёРіСЂС‹ РЅР° СЂСѓСЃСЃРєРѕРј СЏР·С‹РєРµ
function getRussianGameName(gameVersion) {
    const gameMap = {
        'vip_mods': 'VIP РјРѕРґС‹',
        'fs19': 'Farming Simulator 19',
        'fs22': 'Farming Simulator 22', 
        'fs25': 'Farming Simulator 25'
    };
    return gameMap[gameVersion] || gameVersion;
}

// РџСЂСЏРјР°СЏ Р·Р°РіСЂСѓР·РєР° РјРѕРґРѕРІ РёР· Р±Р°Р·С‹ РґР°РЅРЅС‹С…
async function loadModsDirectly(categoryId, gameVersion) {
    // console.log('рџЋ® РџСЂСЏРјР°СЏ Р·Р°РіСЂСѓР·РєР° РјРѕРґРѕРІ РґР»СЏ РєР°С‚РµРіРѕСЂРёРё:', categoryId, 'РёРіСЂР°:', gameVersion);
    
    // РџСЂРѕРІРµСЂСЏРµРј, С‡С‚Рѕ gameVersion РЅРµ СЏРІР»СЏРµС‚СЃСЏ vip_mods РїСЂРё Р·Р°РіСЂСѓР·РєРµ РѕР±С‹С‡РЅС‹С… РјРѕРґРѕРІ
    if (gameVersion === 'vip_mods' && !['Р’СЃРµ', 'fs25', 'fs22', 'fs19'].includes(categoryId)) {
        // console.warn('вљ пёЏ [DEBUG] РџРѕРґРѕР·СЂРёС‚РµР»СЊРЅС‹Р№ РІС‹Р·РѕРІ: gameVersion=vip_mods, categoryId=', categoryId);
    }
    
    if (gameVersion !== 'vip_mods' && ['fs25', 'fs22', 'fs19'].includes(categoryId)) {
        // console.warn('вљ пёЏ [DEBUG] РџРѕРґРѕР·СЂРёС‚РµР»СЊРЅС‹Р№ РІС‹Р·РѕРІ: gameVersion=', gameVersion, ', categoryId=', categoryId);
    }
    
    try {
        // РЎС‚СЂРѕРёРј Р·Р°РїСЂРѕСЃ Рє Р±Р°Р·Рµ РґР°РЅРЅС‹С…
        let query = supabase
            .from('mods')
            .select('*')
            .eq('is_approved', true);

        // РќРѕРІР°СЏ Р»РѕРіРёРєР° РґР»СЏ VIP СЂР°Р·РґРµР»Р°
        if (gameVersion === 'vip_mods') {
            // Р”Р»СЏ VIP СЂР°Р·РґРµР»РѕРІ categoryId РјРѕР¶РµС‚ Р±С‹С‚СЊ:
            // - "Р’СЃРµ" - РїРѕРєР°Р·Р°С‚СЊ РІСЃРµ VIP РјРѕРґС‹ РІСЃРµС… РІРµСЂСЃРёР№ Рё РєР°С‚РµРіРѕСЂРёР№
            // - "fs25", "fs22", "fs19" - РїРѕРєР°Р·Р°С‚СЊ VIP РјРѕРґС‹ РґР»СЏ РєРѕРЅРєСЂРµС‚РЅРѕР№ РІРµСЂСЃРёРё
            // - "objects", "maps", "tractors" Рё С‚.Рґ. - РїРѕРєР°Р·Р°С‚СЊ VIP РјРѕРґС‹ РґР»СЏ РєРѕРЅРєСЂРµС‚РЅРѕР№ РєР°С‚РµРіРѕСЂРёРё
            if (categoryId === 'Р’СЃРµ') {
                // РџРѕРєР°Р·С‹РІР°РµРј РІСЃРµ VIP РјРѕРґС‹ РІСЃРµС… РІРµСЂСЃРёР№
                query = query.eq('is_private', true);
                // вњ… РЈР‘Р РђРќРћ: showVipCategories('main'); - С‚РµРїРµСЂСЊ СѓРїСЂР°РІР»СЏРµС‚СЃСЏ РІ switchGameVersion
            } else if (['fs25', 'fs22', 'fs19'].includes(categoryId)) {
                // РџРѕРєР°Р·С‹РІР°РµРј VIP РјРѕРґС‹ РґР»СЏ РєРѕРЅРєСЂРµС‚РЅРѕР№ РІРµСЂСЃРёРё РёРіСЂС‹
                query = query.eq('is_private', true).eq('game_version', categoryId);
                // вњ… РЈР‘Р РђРќРћ: showVipCategories(categoryId); - С‚РµРїРµСЂСЊ СѓРїСЂР°РІР»СЏРµС‚СЃСЏ РІ switchGameVersion
            } else {
                // РџРѕРєР°Р·С‹РІР°РµРј VIP РјРѕРґС‹ РґР»СЏ РєРѕРЅРєСЂРµС‚РЅРѕР№ РєР°С‚РµРіРѕСЂРёРё (РІСЃРµ РІРµСЂСЃРёРё)
                query = query.eq('is_private', true).eq('category', categoryId);
                // РћСЃС‚Р°РµРјСЃСЏ РІ С‚РµРєСѓС‰РµРј VIP РєРѕРЅС‚РµР№РЅРµСЂРµ
            }
        } else {
            // РЎС‚Р°СЂР°СЏ Р»РѕРіРёРєР° РґР»СЏ РѕР±С‹С‡РЅС‹С… РёРіСЂ - РёСЃРєР»СЋС‡Р°РµРј VIP РјРѕРґС‹
            query = query.eq('game_version', gameVersion).eq('is_private', false);
            if (categoryId !== 'Р’СЃРµ') {
                // РЎРѕРїРѕСЃС‚Р°РІР»РµРЅРёРµ РєР°С‚РµРіРѕСЂРёР№ РґР»СЏ СЃРѕРІРјРµСЃС‚РёРјРѕСЃС‚Рё
                let searchCategory = categoryId;
                if (categoryId === 'russian_mods') {
                    searchCategory = 'russian'; // РС‰РµРј РІ Р±Р°Р·Рµ С‚Рѕ, С‡С‚Рѕ СЂРµР°Р»СЊРЅРѕ СЃРѕС…СЂР°РЅРµРЅРѕ
                }
                query = query.eq('category', searchCategory);
            }
        }

        // Р”РѕР±Р°РІР»СЏРµРј СЃРѕСЂС‚РёСЂРѕРІРєСѓ Рё Р»РёРјРёС‚
        query = query
            .order('created_at', { ascending: false })
            .limit(20);

        // рџ•µпёЏвЂЌв™‚пёЏ Р”РРђР“РќРћРЎРўРРљРђ: Р›РѕРіРёСЂСѓРµРј РїР°СЂР°РјРµС‚СЂС‹ Р·Р°РїСЂРѕСЃР°
        // РџСЂРѕРІРµСЂСЏРµРј VIP СЃС‚Р°С‚СѓСЃ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РґР»СЏ РїСЂР°РІРёР»СЊРЅРѕРіРѕ РѕС‚РѕР±СЂР°Р¶РµРЅРёСЏ VIP РјРѕРґРѕРІ
        let currentUserVipStatus = false;
        
        // РџРѕР»СѓС‡Р°РµРј Р°РєС‚СѓР°Р»СЊРЅС‹Р№ VIP СЃС‚Р°С‚СѓСЃ РёР· Р±Р°Р·С‹
        if (window.authManager?.currentUser) {
            try {
                const { data: profile } = await window.supabase
                    .from('profiles')
                    .select('is_vip, role, vip_expires_at')
                    .eq('id', window.authManager.currentUser.id)
                    .single();

                if (profile) {
                    console.log('рџ”Ќ [VIP РџР РћР’Р•Р РљРђ] РџСЂРѕС„РёР»СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', profile);
                    console.log('рџ”Ќ [VIP РџР РћР’Р•Р РљРђ] is_vip:', profile.is_vip, 'role:', profile.role);
                    
                    // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РџСЂРѕРІРµСЂСЏРµРј Рё is_vip, Рё СЂРѕР»СЊ РґР»СЏ РЅР°РґС‘Р¶РЅРѕСЃС‚Рё
                    const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
                    const hasRoleAccess = vipRoles.includes(profile.role);
                    const hasVipFlag = profile.is_vip === true;
                    const isNotExpired = !profile.vip_expires_at || new Date(profile.vip_expires_at) > new Date();
                    
                    currentUserVipStatus = (hasVipFlag || hasRoleAccess) && isNotExpired;
                    
                    console.log('рџ”Ќ [VIP РџР РћР’Р•Р РљРђ] hasRoleAccess:', hasRoleAccess, 'hasVipFlag:', hasVipFlag, 'isNotExpired:', isNotExpired);
                    console.log('рџ”Ќ [VIP РџР РћР’Р•Р РљРђ] РС‚РѕРіРѕРІС‹Р№ РґРѕСЃС‚СѓРї:', currentUserVipStatus);
                }
            } catch (error) {
                console.warn('вљ пёЏ РћС€РёР±РєР° РїРѕР»СѓС‡РµРЅРёСЏ VIP СЃС‚Р°С‚СѓСЃР°:', error);
                currentUserVipStatus = window.authManager?.currentUser?.is_vip || false;
            }
        }
        
        // console.log('рџ•µпёЏвЂЌв™‚пёЏ Р”РРђР“РќРћРЎРўРРљРђ: Р›РѕРіРёСЂСѓРµРј РїР°СЂР°РјРµС‚СЂС‹ Р·Р°РїСЂРѕСЃР° Рє Supabase:', {
        //     is_approved: true,
        //     is_private: gameVersion === 'vip_mods' ? true : false,
        //     game_version: gameVersion === 'vip_mods' ? categoryId : gameVersion,
        //     category: (gameVersion !== 'vip_mods' && categoryId !== 'Р’СЃРµ') ? categoryId : 'РЅРµ С„РёР»СЊС‚СЂСѓРµРј (VIP)',
        //     mode: gameVersion === 'vip_mods' ? 'VIP' : 'РћР±С‹С‡РЅС‹Р№'
        // });

        const { data: mods, error } = await query;

        if (error) {
            console.error('вќЊ РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё РјРѕРґРѕРІ РёР· Р±Р°Р·С‹ РґР°РЅРЅС‹С…:', error);
            throw error;
        }
        // console.log('вњ… РћС‚РІРµС‚ РѕС‚ Supabase РїРѕР»СѓС‡РµРЅ. РљРѕР»РёС‡РµСЃС‚РІРѕ РјРѕРґРѕРІ:', mods?.length || 0);

        // console.log('вњ… Р—Р°РіСЂСѓР¶РµРЅРѕ РјРѕРґРѕРІ:', mods?.length || 0);

        // РћС‚РѕР±СЂР°Р¶Р°РµРј РјРѕРґС‹
        const modsContainer = document.getElementById('modsContainer');
        if (!modsContainer) {
            // console.error('вќЊ РљРѕРЅС‚РµР№РЅРµСЂ РјРѕРґРѕРІ РЅРµ РЅР°Р№РґРµРЅ');
            return;
        }
        // РРЎРџР РђР’Р›Р•РќРР•: Р”РѕР±Р°РІР»СЏРµРј РіРѕСЂРёР·РѕРЅС‚Р°Р»СЊРЅС‹Р№ РѕС‚СЃС‚СѓРї Рє РєРѕРЅС‚РµР№РЅРµСЂСѓ РјРѕРґРѕРІ
        modsContainer.style.padding = '0 3cm';
        modsContainer.style.boxSizing = 'border-box'; // РЈР±РµРґРёРјСЃСЏ, С‡С‚Рѕ padding СѓС‡РёС‚С‹РІР°РµС‚СЃСЏ РІ РѕР±С‰РµР№ С€РёСЂРёРЅРµ


        if (!mods || mods.length === 0) {
            const russianCategoryName = getRussianCategoryName(categoryId);
            const russianGameName = getRussianGameName(gameVersion);
            modsContainer.innerHTML = `
                <div style="text-align: center; padding: 3rem; color: #f44336;">
                    <h3>рџ“¦ РњРѕРґС‹ РЅРµ РЅР°Р№РґРµРЅС‹</h3>
                    <p>Р”Р»СЏ РёРіСЂС‹ "${russianCategoryName}" РІ РєР°С‚РµРіРѕСЂРёРё ${russianGameName}, РјРѕРґРѕРІ РїРѕРєР° РЅРµС‚.</p>
                    <p>Р—Р°РіСЂСѓР·РёС‚Рµ РјРѕРґС‹ С‡РµСЂРµР· Р°РґРјРёРЅ РїР°РЅРµР»СЊ РёР»Рё РґРѕР±Р°РІСЊС‚Рµ РёС… РІСЂСѓС‡РЅСѓСЋ РІ Р±Р°Р·Сѓ РґР°РЅРЅС‹С….</p>
                </div>
            `;
            return;
        }

        // РЎРѕР·РґР°РµРј HTML РґР»СЏ РјРѕРґРѕРІ
        let modsHtml = '';
        // РРЎРџР РђР’Р›Р•РќРР•: Р—Р°РјРµРЅСЏРµРј forEach РЅР° Р°СЃРёРЅС…СЂРѕРЅРЅС‹Р№ С†РёРєР» for...of РґР»СЏ РєРѕСЂСЂРµРєС‚РЅРѕР№ СЂР°Р±РѕС‚С‹ СЃ await
        for (const mod of mods) {
            // РљРѕСЂСЂРµРєС‚РЅРѕ РґРѕР¶РёРґР°РµРјСЃСЏ СЂРµР·СѓР»СЊС‚Р°С‚Р° РїСЂРѕРІРµСЂРєРё РїСЂР°РІ
            // вњ… РРЎРџР РђР’Р›Р•РќРР•: РљРЅРѕРїРєР° "Р РµРґР°РєС‚РёСЂРѕРІР°С‚СЊ" СѓР±СЂР°РЅР° РёР· РѕР±С‰РµРіРѕ СЃРїРёСЃРєР°.
            // РћРЅР° Р±СѓРґРµС‚ РґРѕСЃС‚СѓРїРЅР° С‚РѕР»СЊРєРѕ РІ РјРѕРґР°Р»СЊРЅРѕРј РѕРєРЅРµ "РџРѕРґСЂРѕР±РЅРµРµ".
            const editButtonHtml = '';
            
            // Р—Р°РіСЂСѓР¶Р°РµРј СЃС‚Р°С‚РёСЃС‚РёРєСѓ РґР»СЏ РєР°Р¶РґРѕРіРѕ РјРѕРґР°
            let avgRating = 0;
            let commentCount = 0;
            
            try {
                // РџРѕР»СѓС‡Р°РµРј СЂРµР№С‚РёРЅРі РјРѕРґР°
                const { data: ratings } = await window.supabase
                    .from('mod_ratings')
                    .select('rating')
                    .eq('mod_id', mod.id);
                
                if (ratings && ratings.length > 0) {
                    avgRating = ratings.reduce((sum, r) => sum + r.rating, 0) / ratings.length;
                }
                
                // РџРѕР»СѓС‡Р°РµРј РєРѕР»РёС‡РµСЃС‚РІРѕ РєРѕРјРјРµРЅС‚Р°СЂРёРµРІ
                const { count } = await window.supabase
                    .from('mod_comments')
                    .select('*', { count: 'exact', head: true })
                    .eq('mod_id', mod.id)
                    .eq('is_deleted', false);
                
                commentCount = count || 0;
            } catch (error) {
                console.warn('вљ пёЏ РќРµ СѓРґР°Р»РѕСЃСЊ Р·Р°РіСЂСѓР·РёС‚СЊ СЃС‚Р°С‚РёСЃС‚РёРєСѓ РґР»СЏ РјРѕРґР°:', mod.id, error);
            }
            
            // РџРѕР»СѓС‡Р°РµРј РїРµСЂРІРѕРµ РёР·РѕР±СЂР°Р¶РµРЅРёРµ РјРѕРґР° РґР»СЏ РїСЂРµРІСЊСЋ
            const cacheBuster = Date.now(); // Р”Р»СЏ РѕР±РЅРѕРІР»РµРЅРёСЏ РєСЌС€Р°
            let mainImageUrl = 'data:image/svg+xml;base64,'; // Р—Р°РіР»СѓС€РєР°
            if (mod.images && Array.isArray(mod.images) && mod.images.length > 0 && mod.images[0]) {
                // РџСЂРѕРІРµСЂСЏРµРј, СЏРІР»СЏРµС‚СЃСЏ Р»Рё РїРµСЂРІС‹Р№ СЌР»РµРјРµРЅС‚ РѕР±СЉРµРєС‚РѕРј СЃ URL РёР»Рё РїСЂРѕСЃС‚Рѕ СЃС‚СЂРѕРєРѕР№
                const firstImg = mod.images[0];
                if (typeof firstImg === 'object' && firstImg.url) {
                    mainImageUrl = firstImg.url + (firstImg.url.includes('?') ? '&' : '?') + 't=' + cacheBuster;
                } else if (typeof firstImg === 'string') {
                    if (firstImg.startsWith('data:image')) {
                        mainImageUrl = firstImg; // Base64 Р±РµР· cache buster
                    } else if (firstImg.startsWith('http')) {
                        mainImageUrl = firstImg + (firstImg.includes('?') ? '&' : '?') + 't=' + cacheBuster;
                    } else {
                        mainImageUrl = `https://gtixajbcfxwqrtsdxnif.supabase.co/storage/v1/object/public/site-assets/${firstImg}?t=${cacheBuster}`;
                    }
                }
            }

        // РџСЂРѕРІРµСЂСЏРµРј VIP СЃС‚Р°С‚СѓСЃ РјРѕРґР° Рё РґРѕСЃС‚СѓРї РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
        // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РџСЂРѕРІРµСЂСЏРµРј Рё is_private, Рё category
        const isVipMod = mod.is_private === true || mod.category === 'vip_mods';
        const hasVipAccess = currentUserVipStatus || false;
        const canAccessVipMod = isVipMod && hasVipAccess;

        console.log(`рџ”Ќ [РљРђР РўРћР§РљРђ] РњРѕРґ "${mod.name}":`, {
            isVipMod,
            is_private: mod.is_private,
            category: mod.category,
            hasVipAccess,
            currentUserVipStatus
        });

        const vipBadge = isVipMod && hasVipAccess ? '<span style="background: linear-gradient(45deg, #ffd700, #ffed4e); color: #000; padding: 4px 8px; border-radius: 12px; font-size: 0.8rem; font-weight: bold; margin-left: 8px;">рџ’Ћ VIP</span>' : '';
        const vipOnlyBadge = isVipMod && !hasVipAccess ? '<span style="background: linear-gradient(45deg, #f44336, #e53935); color: white; padding: 4px 8px; border-radius: 12px; font-size: 0.8rem; font-weight: bold; margin-left: 8px;">рџ”’ VIP</span>' : '';
        
        // РћСЃРѕР±С‹Р№ СЃС‚РёР»СЊ РґР»СЏ VIP РјРѕРґРѕРІ
        const cardStyle = isVipMod 
            ? 'background: linear-gradient(135deg, #1a2f5e, #2a3f6e); border: 2px solid #ffd700; box-shadow: 0 0 20px rgba(255, 215, 0, 0.3);'
            : 'background: linear-gradient(135deg, #112240, #1a2f5e); border: 1px solid rgba(79, 195, 247, 0.2);';

        modsHtml += `
                <div class="mod-card ${isVipMod ? 'vip-mod' : ''}" style="${cardStyle} border-radius: 15px; overflow: hidden; margin: 1rem auto; padding: 1.5rem; width: 100%; max-width: 950px; box-sizing: border-box;">
                    ${isVipMod ? '<div style="text-align: center; margin-bottom: 1rem;"><span style="background: linear-gradient(45deg, #ffd700, #ffed4e); color: #000; padding: 6px 12px; border-radius: 20px; font-size: 0.9rem; font-weight: bold;">рџ’Ћ VIP РњРћР”</span></div>' : ''}
                    <div class="mod-card-image-container" style="margin-bottom: 1rem; border-radius: 10px; overflow: hidden; background: #0a192f;">
                    <img data-src="${mainImageUrl}" src="data:image/svg+xml;base64," alt="РџСЂРµРІСЊСЋ РјРѕРґР° ${mod.name}" loading="lazy" style="width: 100%; height: auto; display: block; aspect-ratio: 16 / 9; object-fit: cover;" onerror="this.src='data:image/svg+xml;base64,';">
                    </div>
                <h3 style="color: ${isVipMod ? '#ffd700' : '#4fc3f7'}; margin: 0 0 1rem 0;">${sanitizeHTML(mod.name)}${vipBadge}${vipOnlyBadge}</h3>
                <p style="color: #8892b0; margin: 0 0 1rem 0;">${sanitizeHTML(mod.description) || 'РћРїРёСЃР°РЅРёРµ РѕС‚СЃСѓС‚СЃС‚РІСѓРµС‚'}</p>
                    <div style="display: flex; gap: 1rem; margin-bottom: 1rem; font-size: 0.9rem; color: #8892b0;">
                        <span>рџ“‚ ${getRussianCategoryName(mod.category) || 'Р‘РµР· РєР°С‚РµРіРѕСЂРёРё'}</span>
                        <span>рџЋ® ${getRussianGameName(mod.game_version)}</span>
                        <span>рџ“Џ ${mod.file_size ? (mod.file_size / 1024 / 1024).toFixed(2) + 'MB' : 'Р Р°Р·РјРµСЂ РЅРµРёР·РІРµСЃС‚РµРЅ'}</span>
                    </div>
                    <div style="display: flex; gap: 0.5rem;">
                        <button onclick="handleDownloadClick('${mod.id}')" style="background: ${isVipMod ? (hasVipAccess ? 'linear-gradient(45deg, #ffd700, #ffed4e)' : 'linear-gradient(45deg, #9e9e9e, #757575)') : 'linear-gradient(135deg, #1a237e, #283593)'}; color: ${isVipMod ? (hasVipAccess ? '#000' : '#fff') : 'white'}; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer; font-weight: bold; ${isVipMod && !hasVipAccess ? 'opacity: 0.6; cursor: not-allowed;' : ''}">${isVipMod && !hasVipAccess ? 'рџ”’ VIP' : 'в¬‡пёЏ РЎРєР°С‡Р°С‚СЊ'}</button>
                        <button onclick="window.showModDetails('${mod.id}')" style="background: #2196F3; color: white; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer;">рџ‘ЃпёЏ РџРѕРґСЂРѕР±РЅРµРµ</button>
                        ${editButtonHtml}
                     </div>
                     
                     <!-- РЎС‡РµС‚С‡РёРєРё СЃС‚Р°С‚РёСЃС‚РёРєРё -->
                     <div style="display: flex; justify-content: space-between; gap: 8px; margin-top: 10px; font-size: 12px;">
                         <div style="background: ${isVipMod ? 'rgba(255,215,0,0.2)' : 'rgba(33,150,243,0.1)'}; border: 1px solid ${isVipMod ? '#FFD700' : '#2196F3'}; border-radius: 12px; padding: 4px 8px; display: flex; align-items: center; gap: 4px; flex: 1; justify-content: center;">
                             <span style="font-size: 12px;">рџ’¬</span>
                             <span style="color: ${isVipMod ? '#FFD700' : '#2196F3'}; font-weight: bold;">${commentCount}</span>
                         </div>
                         
                         <div style="background: ${isVipMod ? 'rgba(255,215,0,0.2)' : 'rgba(26,35,126,0.1)'}; border: 1px solid ${isVipMod ? '#FFD700' : '#1a237e'}; border-radius: 12px; padding: 4px 8px; display: flex; align-items: center; gap: 4px; flex: 1; justify-content: center;">
                             <span style="font-size: 12px;">в¬‡пёЏ</span>
                             <span style="color: ${isVipMod ? '#FFD700' : '#1a237e'}; font-weight: bold;">${mod.download_count || 0}</span>
                         </div>
                         
                         <div style="background: ${isVipMod ? 'rgba(255,215,0,0.2)' : 'rgba(255,193,7,0.1)'}; border: 1px solid ${isVipMod ? '#FFD700' : '#FFC107'}; border-radius: 12px; padding: 4px 8px; display: flex; align-items: center; gap: 4px; flex: 1; justify-content: center;">
                             <span style="font-size: 12px;">в­ђ</span>
                             <span style="color: ${isVipMod ? '#FFD700' : '#FFC107'}; font-weight: bold;">${avgRating.toFixed(1)}</span>
                         </div>
                     </div>
                </div>
            `;
        }

        modsContainer.innerHTML = modsHtml;
        
        // РћС‚РєР»СЋС‡Р°РµРј Р°РЅРёРјР°С†РёРё РєР°СЂС‚РѕС‡РµРє РјРѕРґРѕРІ РїРѕСЃР»Рµ Р·Р°РіСЂСѓР·РєРё
        setTimeout(disableModCardAnimations, 50);
        
        // console.log('вњ… РњРѕРґС‹ РѕС‚РѕР±СЂР°Р¶РµРЅС‹ РЅР° СЃС‚СЂР°РЅРёС†Рµ');
        // console.log('рџ”Ќ [DEBUG] РљРѕР»РёС‡РµСЃС‚РІРѕ РјРѕРґРѕРІ РІ HTML:', mods?.length || 0);
        // console.log('рџ”Ќ [DEBUG] modsContainer.innerHTML.length:', modsContainer.innerHTML.length);

        // РРЅРёС†РёР°Р»РёР·Р°С†РёСЏ Р»РµРЅРёРІРѕР№ Р·Р°РіСЂСѓР·РєРё РґР»СЏ РёР·РѕР±СЂР°Р¶РµРЅРёР№ РјРѕРґРѕРІ
        const lazyImages = document.querySelectorAll('img[loading="lazy"]');
        if ('IntersectionObserver' in window) {
            const observer = new IntersectionObserver((entries, observer) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        const img = entry.target;
                        img.src = img.dataset.src;
                        img.removeAttribute('data-src');
                        observer.unobserve(img);
                    }
                });
            });
            lazyImages.forEach(img => observer.observe(img));
        }


    } catch (error) {
        console.error('вќЊ РљСЂРёС‚РёС‡РµСЃРєР°СЏ РѕС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё РјРѕРґРѕРІ:', error);
        const modsContainer = document.getElementById('modsContainer');
        if (modsContainer) {
            modsContainer.innerHTML = `
                <div style="text-align: center; padding: 3rem; color: #f44336;">
                    <h3>вќЊ РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё РјРѕРґРѕРІ</h3>
                    <p>РџСЂРѕРёР·РѕС€Р»Р° РѕС€РёР±РєР° РїСЂРё Р·Р°РіСЂСѓР·РєРµ РјРѕРґРѕРІ: ${error.message}</p>
                    <p>РџСЂРѕРІРµСЂСЊС‚Рµ РїРѕРґРєР»СЋС‡РµРЅРёРµ Рє Р±Р°Р·Рµ РґР°РЅРЅС‹С… Рё РїРѕРїСЂРѕР±СѓР№С‚Рµ РµС‰Рµ СЂР°Р·.</p>
                </div>
            `;
        }
    }
}

// Р—Р°РіСЂСѓР·РєР° РјРѕРґРѕРІ РїРѕ РєР°С‚РµРіРѕСЂРёРё
async function loadModsByCategory(categoryId, gameVersion = null) {
    console.log('рџЋ® Р—Р°РіСЂСѓР·РєР° РјРѕРґРѕРІ РґР»СЏ РєР°С‚РµРіРѕСЂРёРё:', categoryId, 'РёРіСЂР°:', gameVersion);
    
    // Р”РµС‚Р°Р»СЊРЅР°СЏ РѕС‚Р»Р°РґРєР° РґР»СЏ VIP СЂР°Р·РґРµР»РѕРІ
    if (gameVersion === 'vip_mods') {
        console.log('рџ’Ћ VIP СЂРµР¶РёРј:');
        console.log('  - categoryId (РІРµСЂСЃРёСЏ РёРіСЂС‹):', categoryId);
        console.log('  - gameVersion:', gameVersion);
    }
    
    // РћРїСЂРµРґРµР»СЏРµРј РёРіСЂРѕРІСѓСЋ РІРµСЂСЃРёСЋ, РµСЃР»Рё РѕРЅР° РЅРµ РїРµСЂРµРґР°РЅР° СЏРІРЅРѕ
    if (!gameVersion) {
        gameVersion = currentGameVersion || 'fs25';
        console.log('рџЋ® РСЃРїРѕР»СЊР·СѓРµРј РёРіСЂРѕРІСѓСЋ РІРµСЂСЃРёСЋ РїРѕ СѓРјРѕР»С‡Р°РЅРёСЋ:', gameVersion);
    }

    // РџР РћР’Р•Р РљРђ Р”РћРЎРўРЈРџРђ Рљ VIP-РњРћР”РђРњ
    if (gameVersion === 'vip_mods') {
        console.log('рџ’Ћ Р—Р°РїСЂРѕС€РµРЅ VIP-СЂР°Р·РґРµР». РџСЂРѕРІРµСЂСЏРµРј РґРѕСЃС‚СѓРї...');
        
        // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РџРѕР»СѓС‡Р°РµРј Р°РєС‚СѓР°Р»СЊРЅС‹Р№ РїСЂРѕС„РёР»СЊ СЃ РїСЂРёРЅСѓРґРёС‚РµР»СЊРЅС‹Рј РѕР±РЅРѕРІР»РµРЅРёРµРј
        let profile = await getUserRole(true);
        let retryCount = 0;
        
        while (!profile && retryCount < 3) {
            console.log(`вЏі РџСЂРѕС„РёР»СЊ РЅРµ Р·Р°РіСЂСѓР¶РµРЅ, Р¶РґС‘Рј... (${retryCount + 1}/3)`);
            await new Promise(resolve => setTimeout(resolve, 500));
            profile = await getUserRole(true);
            retryCount++;
        }
        
        if (!profile) {
            console.warn('вљ пёЏ РќРµ СѓРґР°Р»РѕСЃСЊ Р·Р°РіСЂСѓР·РёС‚СЊ РїСЂРѕС„РёР»СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ');
            return;
        }

        console.log('рџ”Ќ РџСЂРѕС„РёР»СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', profile);
        console.log('рџ”Ќ isVip:', profile.isVip, 'role:', profile.role);

        // рџљЁ РџР РћР’Р•Р РљРђ РРЎРўР•Р§Р•РќРРЇ VIP РЎРўРђРўРЈРЎРђ
        if (profile && (profile.isVip || profile.role === 'vip') && profile.vipExpiresAt) {
            const expirationDate = new Date(profile.vipExpiresAt);
            const now = new Date();

            console.log('рџ”Ќ РџСЂРѕРІРµСЂРєР° VIP РёСЃС‚РµС‡РµРЅРёСЏ:');
            console.log('рџ“… РўРµРєСѓС‰Р°СЏ РґР°С‚Р°:', now.toISOString());
            console.log('вЏ° Р”Р°С‚Р° РёСЃС‚РµС‡РµРЅРёСЏ VIP:', profile.vipExpiresAt);
            console.log('рџ”„ РСЃС‚РµРєР»Рѕ Р»Рё:', expirationDate < now);

            if (expirationDate < now) {
                console.log('рџ”„ VIP РёСЃС‚РµРє! РћР±РЅРѕРІР»СЏРµРј Р±Р°Р·Сѓ РґР°РЅРЅС‹С…...');

                try {
                    const { error: updateError } = await window.supabase
                        .from('profiles')
                        .update({
                            is_vip: false,
                            vip_expires_at: null,
                            vip_started_at: null,
                            role: 'user'
                        })
                        .eq('id', window.authManager?.currentUser?.id);

                    if (updateError) {
                        console.error('вќЊ РћС€РёР±РєР° РѕР±РЅРѕРІР»РµРЅРёСЏ VIP:', updateError);
                    } else {
                        console.log('вњ… VIP СЃС‚Р°С‚СѓСЃ РѕР±РЅРѕРІР»РµРЅ РІ Р±Р°Р·Рµ РґР°РЅРЅС‹С…');

                        // РћР±РЅРѕРІР»СЏРµРј Р»РѕРєР°Р»СЊРЅС‹Р№ РїСЂРѕС„РёР»СЊ
                        profile.is_vip = false;
                        profile.vip_expires_at = null;
                        profile.vip_started_at = null;
                        profile.role = 'user';

                        // РџРѕРєР°Р·С‹РІР°РµРј СѓРІРµРґРѕРјР»РµРЅРёРµ
                        showNotification('вќЊ Р’Р°С€ VIP СЃС‚Р°С‚СѓСЃ РёСЃС‚РµРє! РЎС‚Р°С‚СѓСЃ РѕР±РЅРѕРІР»РµРЅ РІ СЃРёСЃС‚РµРјРµ.', 'error');

                        // РћР±РЅРѕРІР»СЏРµРј UI
                        if (window.authManager.updateUIForLoggedInUser) {
                            window.authManager.updateUIForLoggedInUser();
                        }

                        // РџРµСЂРµР·Р°РіСЂСѓР¶Р°РµРј СЃС‚СЂР°РЅРёС†Сѓ
                        setTimeout(() => {
                            window.location.reload();
                        }, 2000);

                        return;
                    }
                } catch (error) {
                    console.error('вќЊ РљСЂРёС‚РёС‡РµСЃРєР°СЏ РѕС€РёР±РєР° РїСЂРё РѕР±РЅРѕРІР»РµРЅРёРё VIP:', error);
                }
            }
        }

        const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
        const hasVipAccess = profile && (profile.isVip === true || vipRoles.includes(profile.role) || profile.isOwner === true);

        console.log('рџ”Ќ hasVipAccess:', hasVipAccess, 'profile.isVip:', profile.isVip, 'profile.role:', profile.role);

        if (!hasVipAccess) {
            console.warn('вќЊ Р”РѕСЃС‚СѓРї Рє VIP-РјРѕРґР°Рј Р·Р°РїСЂРµС‰РµРЅ РґР»СЏ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ СЃ СЂРѕР»СЊСЋ:', profile?.role);
            return;
        }
        console.log('вњ… Р”РѕСЃС‚СѓРї Рє VIP-РјРѕРґР°Рј СЂР°Р·СЂРµС€РµРЅ.');
    }
 
     // РћРїСЂРµРґРµР»СЏРµРј РёРіСЂРѕРІСѓСЋ РІРµСЂСЃРёСЋ
     if (!gameVersion) {
         gameVersion = currentGameVersion || 'fs25';
         console.log('рџЋ® РСЃРїРѕР»СЊР·СѓРµРј РёРіСЂРѕРІСѓСЋ РІРµСЂСЃРёСЋ РїРѕ СѓРјРѕР»С‡Р°РЅРёСЋ:', gameVersion);
     }
 
     // РћР±РЅРѕРІР»СЏРµРј Р°РєС‚РёРІРЅС‹Рµ СЃРѕСЃС‚РѕСЏРЅРёСЏ РєР°С‚РµРіРѕСЂРёР№
     updateCategoryStates(categoryId, gameVersion);
 
     // Р—Р°РіСЂСѓР¶Р°РµРј РјРѕРґС‹ РЅР°РїСЂСЏРјСѓСЋ РёР· Р±Р°Р·С‹ РґР°РЅРЅС‹С…
     loadModsDirectly(categoryId, gameVersion);

     // РЎРѕС…СЂР°РЅСЏРµРј РїРѕСЃР»РµРґРЅСЋСЋ РІС‹Р±СЂР°РЅРЅСѓСЋ РєР°С‚РµРіРѕСЂРёСЋ РґР»СЏ С‚РµРєСѓС‰РµР№ РёРіСЂС‹
     if (typeof saveToLocalStorage === 'function') {
        saveToLocalStorage(`lastSelectedCategory_${gameVersion}`, categoryId);
        console.log(`рџ’ѕ РљР°С‚РµРіРѕСЂРёСЏ '${categoryId}' СЃРѕС…СЂР°РЅРµРЅР° РґР»СЏ РёРіСЂС‹ '${gameVersion}'`);
     }
}

// РџРµСЂРµРєР»СЋС‡РµРЅРёРµ РІРµСЂСЃРёРё РёРіСЂС‹
// РЈР”РђР›Р•РќРћ: Р”СѓР±Р»РёСЂСѓСЋС‰Р°СЏ С„СѓРЅРєС†РёСЏ switchGameVersion - С‚РµРїРµСЂСЊ РёСЃРїРѕР»СЊР·СѓРµС‚СЃСЏ С‚РѕР»СЊРєРѕ РѕРґРЅР° С„СѓРЅРєС†РёСЏ РЅРёР¶Рµ (СЃС‚СЂРѕРєР° 4198)

// РџРѕРєР°Р· РєР°С‚РµРіРѕСЂРёР№ РґР»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ РёРіСЂС‹
function showGameCategories(gameVersion) {
    // РЎРєСЂС‹РІР°РµРј РІСЃРµ РєР°С‚РµРіРѕСЂРёРё
    const allCategories = document.querySelectorAll('.game-categories');
    allCategories.forEach(categories => {
        categories.classList.remove('active');
    });

    // РџРѕРєР°Р·С‹РІР°РµРј РєР°С‚РµРіРѕСЂРёРё РґР»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ РёРіСЂС‹
    const targetCategories = document.getElementById(`${gameVersion}Categories`);
    if (targetCategories) {
        targetCategories.classList.add('active');

        // РћР±РЅРѕРІР»СЏРµРј Р°РєС‚РёРІРЅСѓСЋ РєРЅРѕРїРєСѓ РєР°С‚РµРіРѕСЂРёРё РЅР° "Р’СЃРµ РјРѕРґС‹"
        const allModsBtn = targetCategories.querySelector('.category-btn');
        if (allModsBtn) {
            // РЎРЅРёРјР°РµРј Р°РєС‚РёРІРЅРѕРµ СЃРѕСЃС‚РѕСЏРЅРёРµ СЃРѕ РІСЃРµС… РєР°С‚РµРіРѕСЂРёР№
            const allCategoryBtns = document.querySelectorAll('.category-btn');
            allCategoryBtns.forEach(btn => btn.classList.remove('active'));

            // Р”РµР»Р°РµРј Р°РєС‚РёРІРЅРѕР№ РєРЅРѕРїРєСѓ "Р’СЃРµ РјРѕРґС‹"
            allModsBtn.classList.add('active');
        }
    } else {
        console.error('рџ“‚ РљРѕРЅС‚РµР№РЅРµСЂ РєР°С‚РµРіРѕСЂРёР№ РЅРµ РЅР°Р№РґРµРЅ:', `${gameVersion}Categories`);
    }

    console.log('рџ“‚ РџРѕРєР°Р·Р°РЅС‹ РєР°С‚РµРіРѕСЂРёРё РґР»СЏ:', gameVersion);
}

// РџРѕРєР°Р· VIP РєР°С‚РµРіРѕСЂРёР№ РґР»СЏ РєРѕРЅРєСЂРµС‚РЅРѕР№ РІРµСЂСЃРёРё
function showVipCategories(version) {
    // РЎРєСЂС‹РІР°РµРј РІСЃРµ VIP РєР°С‚РµРіРѕСЂРёРё
    const allVipCategories = document.querySelectorAll('[id^="vip_"]');
    allVipCategories.forEach(categories => {
        categories.classList.remove('active');
    });

    // РџРѕРєР°Р·С‹РІР°РµРј РЅСѓР¶РЅС‹Р№ VIP РєРѕРЅС‚РµР№РЅРµСЂ
    let targetContainer;
    if (version === 'main') {
        targetContainer = document.getElementById('vip_modsCategories');
    } else {
        targetContainer = document.getElementById(`vip_${version}Categories`);
    }

    if (targetContainer) {
        targetContainer.classList.add('active');
        
        // РђРєС‚РёРІРёСЂСѓРµРј РїРµСЂРІСѓСЋ РєРЅРѕРїРєСѓ РєР°С‚РµРіРѕСЂРёР№
        const firstBtn = targetContainer.querySelector('.category-btn');
        if (firstBtn) {
            // РЎРЅРёРјР°РµРј Р°РєС‚РёРІРЅРѕРµ СЃРѕСЃС‚РѕСЏРЅРёРµ СЃРѕ РІСЃРµС… РєР°С‚РµРіРѕСЂРёР№
            const allCategoryBtns = document.querySelectorAll('.category-btn');
            allCategoryBtns.forEach(btn => btn.classList.remove('active'));
            
            // Р”РµР»Р°РµРј Р°РєС‚РёРІРЅРѕР№ РїРµСЂРІСѓСЋ РєРЅРѕРїРєСѓ
            firstBtn.classList.add('active');
        }
    } else {
        console.error('рџ’Ћ VIP РєРѕРЅС‚РµР№РЅРµСЂ РЅРµ РЅР°Р№РґРµРЅ:', version);
    }
}

// Р—Р°РіСЂСѓР·РєР° РїРѕСЃР»РµРґРЅРµР№ РІС‹Р±СЂР°РЅРЅРѕР№ РёРіСЂС‹ РїСЂРё СЃС‚Р°СЂС‚Рµ СЃС‚СЂР°РЅРёС†С‹
function loadLastSelectedGame() {
    try {
        const lastGame = (typeof storageManager !== 'undefined' && typeof storageManager.getLocalStorage === 'function')
            ? (storageManager.getLocalStorage('selectedGameVersion') || 'fs25')
            : (localStorage.getItem('selectedGameVersion') || 'fs25');

        const lastCategory = (typeof storageManager !== 'undefined' && typeof storageManager.getLocalStorage === 'function')
            ? (storageManager.getLocalStorage(`lastSelectedCategory_${lastGame}`) || 'Р’СЃРµ')
            : (localStorage.getItem(`lastSelectedCategory_${lastGame}`) || 'Р’СЃРµ');
        
        currentGameVersion = lastGame;

        // РџРѕРєР°Р·С‹РІР°РµРј РєР°С‚РµРіРѕСЂРёРё РґР»СЏ РїРѕСЃР»РµРґРЅРµР№ РІС‹Р±СЂР°РЅРЅРѕР№ РёРіСЂС‹ Рё Р·Р°РіСЂСѓР¶Р°РµРј РјРѕРґС‹
        setTimeout(() => {
            switchGameVersion(lastGame, lastCategory); // РџРµСЂРµРґР°РµРј Рё РєР°С‚РµРіРѕСЂРёСЋ
        }, 200); // РЈРјРµРЅСЊС€Р°РµРј Р·Р°РґРµСЂР¶РєСѓ РґР»СЏ Р±РѕР»РµРµ Р±С‹СЃС‚СЂРѕР№ Р·Р°РіСЂСѓР·РєРё
    } catch (error) {
        console.error("РћС€РёР±РєР° РїСЂРё Р·Р°РіСЂСѓР·РєРµ РїРѕСЃР»РµРґРЅРµР№ РёРіСЂС‹/РєР°С‚РµРіРѕСЂРёРё:", error);
        // Р’ СЃР»СѓС‡Р°Рµ РѕС€РёР±РєРё Р·Р°РіСЂСѓР¶Р°РµРј РЅР°СЃС‚СЂРѕР№РєРё РїРѕ СѓРјРѕР»С‡Р°РЅРёСЋ
        setTimeout(() => switchGameVersion('fs25', 'Р’СЃРµ'), 200);
    }
}

// РћР±РЅРѕРІР»РµРЅРёРµ С†РІРµС‚РѕРІ Р·Р°РіРѕР»РѕРІРєРѕРІ РєР°С‚РµРіРѕСЂРёР№
function updateCategoryTitles(gameVersion) {
    const titleElements = document.querySelectorAll('.category-game-title');

    titleElements.forEach(title => {
        // РЈР±РёСЂР°РµРј РІСЃРµ С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ Р·Р°РіРѕР»РѕРІРєРѕРІ
        title.classList.remove('fs25-title-color', 'fs22-title-color', 'fs19-title-color', 'vip-title-color');

        // РќР°С…РѕРґРёРј СЂРѕРґРёС‚РµР»СЊСЃРєРёР№ РєРѕРЅС‚РµР№РЅРµСЂ РєР°С‚РµРіРѕСЂРёР№
        const parentContainer = title.closest('.game-categories');
        if (!parentContainer) return;

        // РџСЂРёРјРµРЅСЏРµРј С†РІРµС‚Р° С‚РѕР»СЊРєРѕ РґР»СЏ Р°РєС‚РёРІРЅРѕРіРѕ РєРѕРЅС‚РµР№РЅРµСЂР°
        if (parentContainer.classList.contains('active')) {
            // Р”РѕР±Р°РІР»СЏРµРј СЃРѕРѕС‚РІРµС‚СЃС‚РІСѓСЋС‰РёР№ РєР»Р°СЃСЃ РґР»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ РёРіСЂС‹
            const titleClassMap = {
                'fs25': 'fs25-title-color',
                'fs22': 'fs22-title-color',
                'fs19': 'fs19-title-color',
                'vip_mods': 'vip-title-color'
            };

            const titleClass = titleClassMap[gameVersion];
            if (titleClass) {
                title.classList.add(titleClass);
            }

            // РћРїСЂРµРґРµР»СЏРµРј С†РІРµС‚ С‚РµРєСЃС‚Р° Рё СЌРјРѕРґР·Рё РІ Р·Р°РІРёСЃРёРјРѕСЃС‚Рё РѕС‚ РёРіСЂС‹
            switch(gameVersion) {
                case 'fs25':
                    title.textContent = 'рџџў Farming Simulator 25';
                    break;
                case 'fs22':
                    title.textContent = 'рџ”µ Farming Simulator 22';
                    break;
                case 'fs19':
                    title.textContent = 'рџџЎ Farming Simulator 19';
                    break;
                case 'vip_mods':
                    title.textContent = 'рџ’Ћ VIP РњРѕРґС‹';
                    break;
            }
        }
    });
}

// РџСЂРёРјРµРЅРµРЅРёРµ С†РІРµС‚РѕРІРѕР№ С‚РµРјС‹ Рє Р°РґРјРёРЅ-РїР°РЅРµР»Рё
function applyAdminPanelTheme(gameVersion) {
    const adminPanel = document.getElementById('admin-panel');
    if (!adminPanel) return;

    // РЈР±РёСЂР°РµРј РІСЃРµ С‚РµРјР°С‚РёС‡РµСЃРєРёРµ РєР»Р°СЃСЃС‹
    adminPanel.classList.remove('fs25-theme', 'fs22-theme', 'fs19-theme', 'vip-theme');

    // Р”РѕР±Р°РІР»СЏРµРј СЃРѕРѕС‚РІРµС‚СЃС‚РІСѓСЋС‰РёР№ С‚РµРјР°С‚РёС‡РµСЃРєРёР№ РєР»Р°СЃСЃ
    const themeMap = {
        'fs25': 'fs25-theme',
        'fs22': 'fs22-theme', 
        'fs19': 'fs19-theme',
        'vip_mods': 'vip-theme'
    };

    const themeClass = themeMap[gameVersion];
    if (themeClass) {
        adminPanel.classList.add(themeClass);
        console.log(`рџЋЁ РџСЂРёРјРµРЅРµРЅР° С†РІРµС‚РѕРІР°СЏ С‚РµРјР° Р°РґРјРёРЅ-РїР°РЅРµР»Рё: ${themeClass}`);
    }
}

// Р—Р°РіСЂСѓР·РєР° СЃС‡РµС‚С‡РёРєРѕРІ РјРѕРґРѕРІ РґР»СЏ РєР°С‚РµРіРѕСЂРёР№
async function loadCategoriesModCount(gameVersion) {
    try {
        
        // Р”Р»СЏ VIP СЂР°Р·РґРµР»РѕРІ РёСЃРїРѕР»СЊР·СѓРµРј СЃРїРµС†РёР°Р»СЊРЅСѓСЋ Р»РѕРіРёРєСѓ
        let query = supabase
            .from('mods')
            .select('category, game_version')
            .eq('is_approved', true);
            
        if (gameVersion === 'vip_mods') {
            // Р”Р»СЏ VIP СЂР°Р·РґРµР»РѕРІ СЃС‡РёС‚Р°РµРј С‚РѕР»СЊРєРѕ VIP РјРѕРґС‹
            query = query.eq('is_private', true);
        } else {
            // Р”Р»СЏ РѕР±С‹С‡РЅС‹С… СЂР°Р·РґРµР»РѕРІ СЃС‡РёС‚Р°РµРј С‚РѕР»СЊРєРѕ РѕР±С‹С‡РЅС‹Рµ РјРѕРґС‹
            query = query.eq('is_private', false).eq('game_version', gameVersion);
        }

        const { data: mods, error } = await query;

        if (error) throw error;
        
        // РЎС‡РёС‚Р°РµРј РєРѕР»РёС‡РµСЃС‚РІРѕ РјРѕРґРѕРІ РїРѕ РєР°С‚РµРіРѕСЂРёСЏРј
        const categoryCounts = {};
        if (mods) {
            mods.forEach(mod => {
                let category = mod.category || 'other';
                
                // РЎРѕРїРѕСЃС‚Р°РІР»РµРЅРёРµ РєР°С‚РµРіРѕСЂРёР№ РґР»СЏ СЃРѕРІРјРµСЃС‚РёРјРѕСЃС‚Рё
                const categoryMapping = {
                    'animal_husbandry': 'animals',
                    'rail_transport': 'railway',
                    'loaders_excavators': 'loaders',
                    'forestry_equipment': 'forestry',
                    'baling_equipment': 'baling',
                    'russian': 'russian_mods'
                };
                
                // РџСЂРёРІРѕРґРёРј РєР°С‚РµРіРѕСЂРёСЋ Рє С„РѕСЂРјР°С‚Сѓ РёР· HTML
                if (categoryMapping[category]) {
                    category = categoryMapping[category];
                }
                
                categoryCounts[category] = (categoryCounts[category] || 0) + 1;
            });
        }
        
        // РћР±РЅРѕРІР»СЏРµРј СЃС‡РµС‚С‡РёРєРё РІ РєРЅРѕРїРєР°С… РєР°С‚РµРіРѕСЂРёР№
        let categoryButtons;
        if (gameVersion === 'vip_mods') {
            // Р”Р»СЏ VIP СЂР°Р·РґРµР»РѕРІ РЅСѓР¶РЅРѕ РѕРїСЂРµРґРµР»РёС‚СЊ, РєР°РєРѕР№ РєРѕРЅС‚РµР№РЅРµСЂ СЃРµР№С‡Р°СЃ Р°РєС‚РёРІРµРЅ
            const activeVipContainer = document.querySelector('[id^="vip_"].active');
            if (activeVipContainer) {
                categoryButtons = activeVipContainer.querySelectorAll('.category-btn');
            } else {
                // Р•СЃР»Рё РЅРµС‚ Р°РєС‚РёРІРЅРѕРіРѕ РєРѕРЅС‚РµР№РЅРµСЂР°, РёСЃРїРѕР»СЊР·СѓРµРј РѕСЃРЅРѕРІРЅРѕР№
                categoryButtons = document.querySelectorAll('#vip_modsCategories .category-btn');
            }
        } else {
            // Р”Р»СЏ РѕР±С‹С‡РЅС‹С… СЂР°Р·РґРµР»РѕРІ РєР°Рє РѕР±С‹С‡РЅРѕ
            categoryButtons = document.querySelectorAll(`#${gameVersion}Categories .category-btn`);
        }

        categoryButtons.forEach(button => {
            // вњ… РРЎРџР РђР’Р›Р•РќРР•: РџРѕР»СѓС‡Р°РµРј РЅР°Р·РІР°РЅРёРµ РєР°С‚РµРіРѕСЂРёРё Рё РёРєРѕРЅРєСѓ РёР· data-Р°С‚СЂРёР±СѓС‚РѕРІ, Р° РЅРµ РёР· textContent
            const categoryId = button.dataset.categoryId;
            const categoryName = button.dataset.name;
            const icon = button.dataset.icon;
            
            // Р”Р»СЏ VIP СЂР°Р·РґРµР»РѕРІ РїРѕРєР°Р·С‹РІР°РµРј РєРѕР»РёС‡РµСЃС‚РІРѕ VIP РјРѕРґРѕРІ
            let count = 0;
            if (gameVersion === 'vip_mods') {
                // Р”Р»СЏ VIP СЂР°Р·РґРµР»РѕРІ СЃС‡РёС‚Р°РµРј РїРѕ-СЂР°Р·РЅРѕРјСѓ РІ Р·Р°РІРёСЃРёРјРѕСЃС‚Рё РѕС‚ С‚РёРїР° РєР°С‚РµРіРѕСЂРёРё
                if (categoryId === 'Р’СЃРµ') {
                    // "Р’СЃРµ РјРѕРґС‹" - РїРѕРєР°Р·С‹РІР°РµРј РІСЃРµ VIP РјРѕРґС‹
                    count = mods.length;
                } else if (['fs25', 'fs22', 'fs19'].includes(categoryId)) {
                    // VIP FS25, VIP FS22, VIP FS19 - СЃС‡РёС‚Р°РµРј VIP РјРѕРґС‹ РґР»СЏ РєРѕРЅРєСЂРµС‚РЅРѕР№ РІРµСЂСЃРёРё
                    count = mods.filter(mod => mod.game_version === categoryId).length;
                } else {
                    // РћР±С‹С‡РЅС‹Рµ РєР°С‚РµРіРѕСЂРёРё (objects, maps, tractors Рё С‚.Рґ.) - СЃС‡РёС‚Р°РµРј VIP РјРѕРґС‹ РґР»СЏ РєРѕРЅРєСЂРµС‚РЅРѕР№ РєР°С‚РµРіРѕСЂРёРё
                    count = mods.filter(mod => mod.category === categoryId).length;
                }
            } else {
                // Р”Р»СЏ РѕР±С‹С‡РЅС‹С… СЂР°Р·РґРµР»РѕРІ РёСЃРїРѕР»СЊР·СѓРµРј РѕР±С‹С‡РЅСѓСЋ Р»РѕРіРёРєСѓ
                count = categoryCounts[categoryId] || 0;
            }

            // РћР±РЅРѕРІР»СЏРµРј HTML РєРЅРѕРїРєРё, РёСЃРїРѕР»СЊР·СѓСЏ РґР°РЅРЅС‹Рµ РёР· Р°С‚СЂРёР±СѓС‚РѕРІ
            button.innerHTML = `${icon}${categoryName} <span class="category-count-badge">${count}</span>`;
        });

        // рџЋЁ Р’РђР–РќРћ: РџСЂРёРјРµРЅСЏРµРј С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ РїРѕСЃР»Рµ РѕР±РЅРѕРІР»РµРЅРёСЏ СЃС‡РµС‚С‡РёРєРѕРІ
        setTimeout(() => {
            applyCategoryColors();
        }, 100);

        // РћР±РЅРѕРІР»СЏРµРј РєРЅРѕРїРєСѓ "Р’СЃРµ РјРѕРґС‹"
        const allModsBtn = document.querySelector('.category-btn[onclick*="Р’СЃРµ"]');
        if (allModsBtn) {
            const totalCount = mods ? mods.length : 0;
            allModsBtn.innerHTML = `рџ—‚пёЏ Р’СЃРµ РјРѕРґС‹ <span class="category-count-badge">${totalCount}</span>`;
        }

    } catch (error) {
        console.error('РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё СЃС‡РµС‚С‡РёРєРѕРІ РјРѕРґРѕРІ:', error);
    }
}

// РћР±РЅРѕРІР»РµРЅРёРµ Р°РєС‚РёРІРЅС‹С… СЃРѕСЃС‚РѕСЏРЅРёР№ РєР°С‚РµРіРѕСЂРёР№
function updateCategoryStates(activeCategory, gameVersion) {
    // РЎРЅРёРјР°РµРј Р°РєС‚РёРІРЅРѕРµ СЃРѕСЃС‚РѕСЏРЅРёРµ СЃРѕ РІСЃРµС… РєР°С‚РµРіРѕСЂРёР№
    const allCategories = document.querySelectorAll('.category-btn');
    allCategories.forEach(btn => {
        btn.classList.remove('active');
    });

    // РќР°С…РѕРґРёРј Р°РєС‚РёРІРЅСѓСЋ РєР°С‚РµРіРѕСЂРёСЋ Рё СѓСЃС‚Р°РЅР°РІР»РёРІР°РµРј РµР№ Р°РєС‚РёРІРЅРѕРµ СЃРѕСЃС‚РѕСЏРЅРёРµ
    const activeBtn = document.querySelector(`[onclick="loadModsByCategory('${activeCategory}', '${gameVersion}')"]`);
    if (activeBtn) {
        activeBtn.classList.add('active');
    }
}


// Р¤СѓРЅРєС†РёСЏ РѕР±СЂР°Р±РѕС‚РєРё РєР»РёРєР° РЅР° СЃРєР°С‡РёРІР°РЅРёРµ СЃ РїСЂРѕРІРµСЂРєРѕР№ Р±Р»РѕРєРёСЂРѕРІРєРё
async function handleDownloadClick(modId) {
    console.log('рџ”Ќ [РЎРљРђР§РђРўР¬ РљР›РРљ] modId:', modId);
    
    try {
        // РџСЂРѕРІРµСЂСЏРµРј Р°РІС‚РѕСЂРёР·Р°С†РёСЋ
        if (!window.authManager?.currentUser) {
            console.log('вќЊ [РЎРљРђР§РђРўР¬ РљР›РРљ] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ Р°РІС‚РѕСЂРёР·РѕРІР°РЅ');
            showNotification('рџ”’ РќРµРѕР±С…РѕРґРёРјРѕ РІРѕР№С‚Рё РІ СЃРёСЃС‚РµРјСѓ РґР»СЏ СЃРєР°С‡РёРІР°РЅРёСЏ РјРѕРґРѕРІ', 'error');
            showLoginModal();
            return;
        }

        console.log('вњ… [РЎРљРђР§РђРўР¬ РљР›РРљ] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ Р°РІС‚РѕСЂРёР·РѕРІР°РЅ:', window.authManager.currentUser.email);

        // РџР РЇРњРђРЇ РџР РћР’Р•Р РљРђ Р‘Р›РћРљРР РћР’РљР Р’ Р‘Р”
        const profile = await getUserProfileInfo(window.authManager.currentUser.id);
        console.log('рџ”Ќ [РЎРљРђР§РђРўР¬ РљР›РРљ] РџСЂРѕС„РёР»СЊ:', profile);

        if (profile?.is_banned) {
            console.log('вќЊ [РЎРљРђР§РђРўР¬ РљР›РРљ] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ');
            const bannedByInfo = await getBannedByInfo(profile.banned_by);

            showNotification(`рџљ« Р”РѕСЃС‚СѓРї Р·Р°РїСЂРµС‰РµРЅ! Р’Р°С€ Р°РєРєР°СѓРЅС‚ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ. Р—Р°Р±Р»РѕРєРёСЂРѕРІР°Р»: ${bannedByInfo}. РџСЂРёС‡РёРЅР°: ${profile.ban_reason || 'Р“СЂСѓР±С‹Рµ РЅР°СЂСѓС€РµРЅРёСЏ РїСЂР°РІРёР»'}`, 'error');
            return;
        }

        console.log('вњ… [РЎРљРђР§РђРўР¬ РљР›РРљ] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ, РёСЃРїРѕР»СЊР·СѓРµРј Р·Р°С‰РёС‰РµРЅРЅРѕРµ СЃРєР°С‡РёРІР°РЅРёРµ...');
        
        // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РСЃРїРѕР»СЊР·СѓРµРј Р·Р°С‰РёС‰РµРЅРЅСѓСЋ СЃРёСЃС‚РµРјСѓ СЃРєР°С‡РёРІР°РЅРёСЏ
        if (window.secureDownloadManager) {
            console.log('рџ”ђ [РЎРљРђР§РђРўР¬ РљР›РРљ] РСЃРїРѕР»СЊР·СѓРµРј Р·Р°С‰РёС‰РµРЅРЅРѕРµ СЃРєР°С‡РёРІР°РЅРёРµ...');
            await window.secureDownloadManager.downloadModSecure(modId);
            console.log('вњ… [РЎРљРђР§РђРўР¬ РљР›РРљ] Р—Р°С‰РёС‰РµРЅРЅРѕРµ СЃРєР°С‡РёРІР°РЅРёРµ Р·Р°РІРµСЂС€РµРЅРѕ СѓСЃРїРµС€РЅРѕ');
        } else {
            console.warn('вљ пёЏ [РЎРљРђР§РђРўР¬ РљР›РРљ] РњРµРЅРµРґР¶РµСЂ Р·Р°С‰РёС‰РµРЅРЅРѕРіРѕ СЃРєР°С‡РёРІР°РЅРёСЏ РЅРµ РЅР°Р№РґРµРЅ, РёСЃРїРѕР»СЊР·СѓРµРј РѕР±С‹С‡РЅС‹Р№ РјРµС‚РѕРґ...');
            // Fallback Рє РѕР±С‹С‡РЅРѕРјСѓ РјРµС‚РѕРґСѓ
            downloadMod(modId).then(() => {
                console.log('вњ… [РЎРљРђР§РђРўР¬ РљР›РРљ] downloadMod Р·Р°РІРµСЂС€С‘РЅ СѓСЃРїРµС€РЅРѕ');
            }).catch(error => {
                console.error('вќЊ [РЎРљРђР§РђРўР¬ РљР›РРљ] РћС€РёР±РєР° downloadMod:', error);
                showNotification('вќЊ РћС€РёР±РєР° СЃРєР°С‡РёРІР°РЅРёСЏ: ' + error.message, 'error');
            });
        }

    } catch (error) {
        console.error('вќЊ [РЎРљРђР§РђРўР¬ РљР›РРљ] РћС€РёР±РєР°:', error);
        showNotification('вќЊ РћС€РёР±РєР° РїСЂРё РїСЂРѕРІРµСЂРєРµ РґРѕСЃС‚СѓРїР° Рє СЃРєР°С‡РёРІР°РЅРёСЋ', 'error');
    }
}

// Р¤СѓРЅРєС†РёСЏ РґР»СЏ РїРѕР»СѓС‡РµРЅРёСЏ РїСЂР°РІРёР»СЊРЅРѕР№ РёРЅС„РѕСЂРјР°С†РёРё Рѕ РїРѕР»СЊР·РѕРІР°С‚РµР»Рµ (РєР°Рє РІ showBannedUsersList)
async function getUserProfileInfo(userId) {
    try {
        if (!userId) return null;
        
        const { data: profile, error } = await window.supabase
            .from('profiles')
            .select('id, username, email, role, is_banned, ban_reason, banned_by, banned_at, is_vip, vip_expires_at')
            .eq('id', userId)
            .single();
            
        if (error) {
            console.error('вќЊ РћС€РёР±РєР° РїРѕР»СѓС‡РµРЅРёСЏ РїСЂРѕС„РёР»СЏ:', error);
            return null;
        }
        
        return profile;
    } catch (error) {
        console.error('вќЊ РћС€РёР±РєР° РІ getUserProfileInfo:', error);
        return null;
    }
}

// Р¤СѓРЅРєС†РёСЏ РґР»СЏ РїСЂРѕРІРµСЂРєРё СЃС‚Р°С‚СѓСЃР° Р±Р»РѕРєРёСЂРѕРІРєРё РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
async function isUserBanned() {
    try {
        if (!window.authManager?.currentUser) return false;
        
        const profile = await getUserProfileInfo(window.authManager.currentUser.id);
        
        if (!profile) {
            return false;
        }
        
        return profile.is_banned || false;
    } catch (error) {
        console.error('вќЊ РћС€РёР±РєР° РІ isUserBanned:', error);
        return false;
    }
}

// Р¤СѓРЅРєС†РёСЏ РґР»СЏ РїРѕР»СѓС‡РµРЅРёСЏ РёРЅС„РѕСЂРјР°С†РёРё Рѕ С‚РѕРј, РєС‚Рѕ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°Р» РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ (РїРѕ Р°РЅР°Р»РѕРіРёРё СЃ РјРѕРґР°РјРё)
async function getBannedByInfo(bannedById) {
    try {
        if (!bannedById) return 'РќРµРёР·РІРµСЃС‚РЅРѕ';
        
        let bannedByName = 'РќРµРёР·РІРµСЃС‚РЅРѕ';
        
        // РЎРЅР°С‡Р°Р»Р° РїСЂРѕР±СѓРµРј РїРѕР»СѓС‡РёС‚СЊ РїСЂРѕС„РёР»СЊ РїРѕ banned_by
        try {
            const { data: profile } = await window.supabase
                .from('profiles')
                .select('username, email, role')
                .eq('id', bannedById)
                .single();
            
            if (profile) {
                // РЎРїРµС†РёР°Р»СЊРЅР°СЏ РїСЂРѕРІРµСЂРєР° РґР»СЏ KEROS - РїСЂРѕРІРµСЂСЏРµРј РїРѕ email Рё username РЅРµР·Р°РІРёСЃРёРјРѕ РѕС‚ СЂРѕР»Рё
                if (profile.username === 'KEROS' || profile.email === 'ldjone@mail.ru') {
                    bannedByName = `рџ‘‘ KEROS (Р’Р›РђР”Р•Р›Р•Р¦)`;
                } else {
                    // РћРїСЂРµРґРµР»СЏРµРј РѕС‚РѕР±СЂР°Р¶Р°РµРјСѓСЋ СЂРѕР»СЊ РґР»СЏ РѕСЃС‚Р°Р»СЊРЅС‹С… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№
                    const roleDisplay = {
                        'owner': 'рџ‘‘ KEROS/Djone (Р’Р›РђР”Р•Р›Р•Р¦)',
                        'admin_senior': 'рџ’Ћ РЎРўРђР РЁРР™ РђР”РњРРќ', 
                        'admin': 'вљЎ РђР”РњРРќ',
                        'moderator_senior': 'рџ”Ґ РЎРўРђР РЁРР™ РњРћР”Р•Р РђРўРћР ',
                        'moderator': 'рџ›ЎпёЏ РњРћР”Р•Р РђРўРћР ',
                        'vip': 'рџ’Ћ VIP',
                        'user': 'рџ‘¤ РџРћР›Р¬Р—РћР’РђРўР•Р›Р¬'
                    }[profile.role] || 'рџ‘¤ РџРћР›Р¬Р—РћР’РђРўР•Р›Р¬';
                    
                    bannedByName = `${profile.username || profile.email || 'РќРµРёР·РІРµСЃС‚РµРЅ'} (${roleDisplay})`;
                }
            }
        } catch (profileError) {
            console.warn('вљ пёЏ [getBannedByInfo] РќРµ СѓРґР°Р»РѕСЃСЊ РїРѕР»СѓС‡РёС‚СЊ РїСЂРѕС„РёР»СЊ РїРѕ banned_by:', profileError);
        }
        
        // Р•СЃР»Рё РїСЂРѕС„РёР»СЊ РЅРµ РЅР°Р№РґРµРЅ, РїСЂРѕР±СѓРµРј РґСЂСѓРіРёРµ СЃРїРѕСЃРѕР±С‹
        if (bannedByName === 'РќРµРёР·РІРµСЃС‚РµРЅ') {
            // Р—РґРµСЃСЊ РјРѕР¶РЅРѕ РґРѕР±Р°РІРёС‚СЊ РґРѕРїРѕР»РЅРёС‚РµР»СЊРЅС‹Рµ РїСЂРѕРІРµСЂРєРё РµСЃР»Рё РЅСѓР¶РЅРѕ
        }
        
        return bannedByName;
        
    } catch (error) {
        console.error('вќЊ [getBannedByInfo] РћС€РёР±РєР°:', error);
        return 'РќРµРёР·РІРµСЃС‚РЅРѕ';
    }
}

// РџСЂРѕРІРµСЂРєР° СЃС‚Р°С‚СѓСЃР° Р±Р»РѕРєРёСЂРѕРІРєРё РІ СЂРµР°Р»СЊРЅРѕРј РІСЂРµРјРµРЅРё Рё РѕР±РЅРѕРІР»РµРЅРёРµ РёРЅС‚РµСЂС„РµР№СЃР°
window.checkAndUpdateBanStatus = async function() {
    if (!window.authManager?.currentUser?.id) {
        return;
    }
    
    try {
        const { data: profile, error } = await window.supabase
            .from('profiles')
            .select('is_banned, ban_reason, role')
            .eq('id', window.authManager.currentUser.id)
            .single();

        if (error) {
            console.error('вќЊ РћС€РёР±РєР° РїРѕР»СѓС‡РµРЅРёСЏ РїСЂРѕС„РёР»СЏ:', error);
            throw error;
        }

        // console.log('рџ“Љ Р”Р°РЅРЅС‹Рµ РїСЂРѕС„РёР»СЏ:', profile);

        // Р•СЃР»Рё РїРѕР»СЊР·РѕРІР°С‚РµР»СЊ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ, РѕР±РЅРѕРІР»СЏРµРј РёРЅС‚РµСЂС„РµР№СЃ
        if (profile?.is_banned) {
            console.warn('вљ пёЏ РџРћР›Р¬Р—РћР’РђРўР•Р›Р¬ Р—РђР‘Р›РћРљРР РћР’РђРќ! РћР±РЅРѕРІР»СЏРµРј РёРЅС‚РµСЂС„РµР№СЃ');
            
            // РћР±РЅРѕРІР»СЏРµРј authManager СЃ Р°РєС‚СѓР°Р»СЊРЅС‹РјРё РґР°РЅРЅС‹РјРё
            if (window.authManager) {
                window.authManager.currentUser.is_banned = true;
                window.authManager.currentUser.ban_reason = profile.ban_reason;
                window.authManager.currentUser.role = profile.role;
                
                console.log('вњ… AuthManager РѕР±РЅРѕРІР»РµРЅ:', {
                    is_banned: window.authManager.currentUser.is_banned,
                    ban_reason: window.authManager.currentUser.ban_reason,
                    role: window.authManager.currentUser.role
                });
            }
            
            // Р—Р°РєСЂС‹РІР°РµРј РІСЃРµ РјРѕРґР°Р»СЊРЅС‹Рµ РѕРєРЅР°
            document.querySelectorAll('.user-details-modal').forEach(modal => modal.remove());
            
            // РџРѕРєР°Р·С‹РІР°РµРј СѓРІРµРґРѕРјР»РµРЅРёРµ
            showNotification(`рџљ« Р’Р°С€ Р°РєРєР°СѓРЅС‚ Р±С‹Р» Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ. РџСЂРёС‡РёРЅР°: ${profile.ban_reason || 'РќРµ СѓРєР°Р·Р°РЅР°'}. Р”РѕСЃС‚СѓРї Рє СЃРєР°С‡РёРІР°РЅРёСЋ РєРѕРЅС‚РµРЅС‚Р° РѕРіСЂР°РЅРёС‡РµРЅ.`, 'error');
            
            // РџСЂРёРЅСѓРґРёС‚РµР»СЊРЅС‹Р№ РІС‹С…РѕРґ С‡РµСЂРµР· 3 СЃРµРєСѓРЅРґС‹
            setTimeout(async () => {
                try {
                    await window.supabase.auth.signOut();
                    localStorage.clear();
                    sessionStorage.clear();
                    
                    // РџРѕРєР°Р·С‹РІР°РµРј СЃС‚СЂР°РЅРёС†Сѓ Р±Р»РѕРєРёСЂРѕРІРєРё
                    document.body.innerHTML = `
                        <div style="
                            display: flex; 
                            justify-content: center; 
                            align-items: center; 
                            height: 100vh; 
                            background: linear-gradient(135deg, #1a1a2e, #16213e);
                            color: #f44336;
                            font-family: Arial, sans-serif;
                            text-align: center;
                        ">
                            <div>
                                <div style="font-size: 4rem; margin-bottom: 20px;">рџљ«</div>
                                <h1 style="font-size: 2rem; margin-bottom: 15px;">Р”РѕСЃС‚СѓРї Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ</h1>
                                <p style="font-size: 1.2rem; margin-bottom: 10px;">РџСЂРёС‡РёРЅР°: ${profile.ban_reason || 'Р“СЂСѓР±С‹Рµ РЅР°СЂСѓС€РµРЅРёСЏ РїСЂР°РІРёР»'}</p>
                                <p style="color: #ccc; margin-bottom: 20px;">Р’С‹ Р±С‹Р»Рё РІС‹РІРµРґРµРЅС‹ РёР· СЃРёСЃС‚РµРјС‹</p>
                                <button onclick="window.location.reload()" style="background: linear-gradient(135deg, #1a237e, #283593); color: white; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer;">рџ”„ РћР±РЅРѕРІРёС‚СЊ СЃС‚СЂР°РЅРёС†Сѓ</button>
                            </div>
                        </div>
                    `;
                } catch (logoutError) {
                    console.error('вќЊ РћС€РёР±РєР° РІС‹С…РѕРґР°:', logoutError);
                    window.location.reload();
                }
            }, 3000);
        } else {
            // console.log('вњ… РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ');
        }
    } catch (error) {
        console.error('вќЊ РћС€РёР±РєР° РїСЂРѕРІРµСЂРєРё СЃС‚Р°С‚СѓСЃР° Р±Р»РѕРєРёСЂРѕРІРєРё:', error);
    }
};

// Р—Р°РїСѓСЃРєР°РµРј РїРµСЂРёРѕРґРёС‡РµСЃРєСѓСЋ РїСЂРѕРІРµСЂРєСѓ
if (typeof window.authManager !== 'undefined') {
    // РџСЂРѕРІРµСЂСЏРµРј РєР°Р¶РґС‹Рµ 10 СЃРµРєСѓРЅРґ
    setInterval(window.checkAndUpdateBanStatus, 10000);
    
    // РўР°РєР¶Рµ РїСЂРѕРІРµСЂСЏРµРј СЃСЂР°Р·Сѓ РїСЂРё Р·Р°РіСЂСѓР·РєРµ
    setTimeout(window.checkAndUpdateBanStatus, 3000);
    
    // Р РїСЂРѕРІРµСЂСЏРµРј РїСЂРё РєР°Р¶РґРѕРј РєР»РёРєРµ РЅР° РјРѕРґ
    document.addEventListener('click', function(e) {
        if (e.target.closest('button[onclick*="showModDetails"]') || 
            e.target.closest('button[onclick*="downloadMod"]')) {
            setTimeout(window.checkAndUpdateBanStatus, 100);
        }
    });
    
    console.log('рџ”Ќ РџСЂРѕРІРµСЂРєР° Р±Р»РѕРєРёСЂРѕРІРєРё Р·Р°РїСѓС‰РµРЅР°');
} else {
    console.warn('вљ пёЏ AuthManager РЅРµ РЅР°Р№РґРµРЅ, РїСЂРѕРІРµСЂРєР° Р±Р»РѕРєРёСЂРѕРІРєРё РЅРµ СЂР°Р±РѕС‚Р°РµС‚');
}

// Р”РѕР±Р°РІР»СЏРµРј РіР»РѕР±Р°Р»СЊРЅСѓСЋ С„СѓРЅРєС†РёСЋ РґР»СЏ СЂСѓС‡РЅРѕР№ РїСЂРѕРІРµСЂРєРё
window.forceCheckBanStatus = function() {
    console.log('рџ”Ќ РџСЂРёРЅСѓРґРёС‚РµР»СЊРЅР°СЏ РїСЂРѕРІРµСЂРєР° СЃС‚Р°С‚СѓСЃР° Р±Р»РѕРєРёСЂРѕРІРєРё...');
    window.checkAndUpdateBanStatus();
};

// РЎРєР°С‡РёРІР°РЅРёРµ РјРѕРґР°
async function downloadMod(modId) {
    console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] РќР°С‡Р°Р»Рѕ СЃРєР°С‡РёРІР°РЅРёСЏ, modId:', modId);
    
    try {
        const { data: { user } } = await window.supabase.auth.getUser();

        if (!user) {
            console.log('вќЊ [РЎРљРђР§РР’РђРќРР•] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ Р°РІС‚РѕСЂРёР·РѕРІР°РЅ');
            showNotification('РќРµРѕР±С…РѕРґРёРјРѕ РІРѕР№С‚Рё РІ СЃРёСЃС‚РµРјСѓ РґР»СЏ СЃРєР°С‡РёРІР°РЅРёСЏ РјРѕРґРѕРІ', 'error');
            showLoginModal();
            return;
        }

        console.log('вњ… [РЎРљРђР§РР’РђРќРР•] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ:', user.email, 'ID:', user.id);

        // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РџРѕР»СѓС‡Р°РµРј РђРљРўРЈРђР›Р¬РќР«Р™ РїСЂРѕС„РёР»СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
        const { data: profile, error: profileError } = await window.supabase
            .from('profiles')
            .select('is_banned, role, is_vip, vip_expires_at')
            .eq('id', user.id)
            .single();

        if (profileError) {
            console.error('вќЊ [РЎРљРђР§РР’РђРќРР•] РћС€РёР±РєР° РїРѕР»СѓС‡РµРЅРёСЏ РїСЂРѕС„РёР»СЏ:', profileError);
            throw profileError;
        }

        console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] РџСЂРѕС„РёР»СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', profile);
        console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] is_vip:', profile?.is_vip, 'role:', profile?.role);

        // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РџСЂРѕРІРµСЂСЏРµРј Р°РєС‚СѓР°Р»СЊРЅРѕСЃС‚СЊ VIP СЃС‚Р°С‚СѓСЃР°
        if (profile?.is_vip && profile?.vip_expires_at) {
            const now = new Date();
            const expiresAt = new Date(profile.vip_expires_at);
            const isExpired = expiresAt < now;

            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] VIP РёСЃС‚РµРєР°РµС‚:', profile.vip_expires_at);
            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] РўРµРєСѓС‰РµРµ РІСЂРµРјСЏ:', now.toISOString());
            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] РСЃС‚РµРєР»Рѕ Р»Рё:', isExpired);

            if (isExpired) {
                console.log('вљ пёЏ [РЎРљРђР§РР’РђРќРР•] VIP СЃС‚Р°С‚СѓСЃ РёСЃС‚С‘Рє! РћР±РЅРѕРІР»СЏРµРј...');
                await window.supabase
                    .from('profiles')
                    .update({
                        is_vip: false,
                        role: 'user'
                    })
                    .eq('id', user.id);

                showNotification('вќЊ Р’Р°С€ VIP СЃС‚Р°С‚СѓСЃ РёСЃС‚С‘Рє!', 'error');
                return;
            }
        }

        if (profile.is_banned) {
            console.log('вќЊ [РЎРљРђР§РР’РђРќРР•] РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ');
            showNotification('рџљ« Р—Р°Р±Р»РѕРєРёСЂРѕРІР°РЅРЅС‹Рј РїРѕР»СЊР·РѕРІР°С‚РµР»СЏРј Р·Р°РїСЂРµС‰РµРЅРѕ СЃРєР°С‡РёРІР°С‚СЊ РєРѕРЅС‚РµРЅС‚.', 'error');
            return;
        }

        // РџРѕР»СѓС‡Р°РµРј РёРЅС„РѕСЂРјР°С†РёСЋ Рѕ РјРѕРґРµ, РІРєР»СЋС‡Р°СЏ РµРіРѕ РїСЂРёРІР°С‚РЅРѕСЃС‚СЊ Рё СЃСЃС‹Р»РєСѓ РЅР° С„Р°Р№Р»
        const { data: mod, error } = await window.supabase
            .from('mods')
            .select('id, name, is_private, download_url, file_path, category')
            .eq('id', modId)
            .single();

        if (error) {
            console.error('вќЊ [РЎРљРђР§РР’РђРќРР•] РћС€РёР±РєР° РїРѕР»СѓС‡РµРЅРёСЏ РјРѕРґР°:', error);
            throw error;
        }

        console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] РњРѕРґ:', mod);
        console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] is_private:', mod?.is_private);
        console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] category:', mod?.category);

        // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РџСЂРѕРІРµСЂСЏРµРј, СЏРІР»СЏРµС‚СЃСЏ Р»Рё РјРѕРґ VIP (РїРѕ is_private РёР»Рё category)
        const isVipMod = mod?.is_private === true || mod?.category === 'vip_mods';
        console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] isVipMod:', isVipMod);

        // --- РќРћР’РђРЇ Р›РћР“РРљРђ Р”Р›РЇ Р‘Р•Р—РћРџРђРЎРќРћР“Рћ РЎРљРђР§РР’РђРќРРЇ ---
        if (isVipMod) {
            console.log('рџ’Ћ Р­С‚Рѕ VIP-РјРѕРґ. РџСЂРѕРІРµСЂСЏРµРј РґРѕСЃС‚СѓРї...');
            showNotification('рџ’Ћ Р—Р°РїСЂРѕСЃ РґРѕСЃС‚СѓРїР° Рє VIP-С„Р°Р№Р»Сѓ...', 'info');

            // РџСЂРѕРІРµСЂСЏРµРј РїСЂР°РІР° РґРѕСЃС‚СѓРїР° РЅР° РєР»РёРµРЅС‚Рµ РґР»СЏ Р±С‹СЃС‚СЂРѕР№ РѕР±СЂР°С‚РЅРѕР№ СЃРІСЏР·Рё
            const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
            // РРЎРџР РђР’Р›Р•РќРР•: РџСЂРѕРІРµСЂСЏРµРј Рё С„Р»Р°Рі is_vip, Рё СЂРѕР»СЊ РґР»СЏ РЅР°РґРµР¶РЅРѕСЃС‚Рё
            const hasVipAccess = profile && (profile.is_vip === true || vipRoles.includes(profile.role));

            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] VIP РґРѕСЃС‚СѓРї:', hasVipAccess);
            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] profile.is_vip:', profile?.is_vip);
            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] profile.role:', profile?.role);
            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] vipRoles.includes(role):', vipRoles.includes(profile?.role));
            console.log('рџ”Ќ [РЎРљРђР§РР’РђРќРР•] РџРѕР»РЅС‹Р№ РїСЂРѕС„РёР»СЊ:', profile);

            if (!hasVipAccess) {
                console.log('вќЊ [РЎРљРђР§РР’РђРќРР•] РќРµС‚ VIP РґРѕСЃС‚СѓРїР°');
                console.log('вљ пёЏ [РЎРљРђР§РР’РђРќРР•] РџРћРљРђР—Р«Р’РђР•Рњ РЎРћРћР‘Р©Р•РќРР• РћР‘ РћРЁРР‘РљР•');
                showNotification('вќЊ Р­С‚РѕС‚ РјРѕРґ РґРѕСЃС‚СѓРїРµРЅ С‚РѕР»СЊРєРѕ РґР»СЏ VIP-РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№!', 'error');
                return;
            }

            // рџ›ЎпёЏ РќРћР’РђРЇ РЎРРЎРўР•РњРђ Р—РђР©РРўР« VIP РњРћР”РћР’
            console.log('вњ… VIP РґРѕСЃС‚СѓРї СЂР°Р·СЂРµС€С‘РЅ. Р—Р°РїСЂР°С€РёРІР°РµРј Р·Р°С‰РёС‰РµРЅРЅСѓСЋ СЃСЃС‹Р»РєСѓ...');
            showNotification('рџ›ЎпёЏ Р“РµРЅРµСЂР°С†РёСЏ Р·Р°С‰РёС‰РµРЅРЅРѕР№ СЃСЃС‹Р»РєРё...', 'info');

            try {
                // Р—Р°РїСЂР°С€РёРІР°РµРј Р·Р°С‰РёС‰РµРЅРЅСѓСЋ СЃСЃС‹Р»РєСѓ
                const response = await fetch(`${window.supabase.supabaseUrl}/functions/v1/get-vip-secure-download`, {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${ (await window.supabase.auth.getSession()).data.session.access_token }`,
                        'Content-Type': 'application/json',
                        'Referer': window.location.origin
                    },
                    body: JSON.stringify({ modId })
                });

                const data = await response.json();

                if (data.success) {
                    console.log('вњ… Р—Р°С‰РёС‰РµРЅРЅР°СЏ СЃСЃС‹Р»РєР° РїРѕР»СѓС‡РµРЅР°:', data.secureUrl);
                    showNotification('рџ›ЎпёЏ Р—Р°С‰РёС‰РµРЅРЅР°СЏ СЃСЃС‹Р»РєР° СЃРѕР·РґР°РЅР°! РџРµСЂРµРЅР°РїСЂР°РІР»РµРЅРёРµ...', 'success');
                    
                    // РџРµСЂРµРЅР°РїСЂР°РІР»СЏРµРј РЅР° СЃРєР°С‡РёРІР°РЅРёРµ
                    setTimeout(() => {
                        window.location.href = data.secureUrl;
                    }, 1000);
                    
                } else {
                    console.error('вќЊ РћС€РёР±РєР° РїРѕР»СѓС‡РµРЅРёСЏ Р·Р°С‰РёС‰РµРЅРЅРѕР№ СЃСЃС‹Р»РєРё:', data.error);
                    showNotification(`вќЊ ${data.error}`, 'error');
                }
                
            } catch (error) {
                console.error('вќЊ РћС€РёР±РєР° Р·Р°РїСЂРѕСЃР° Р·Р°С‰РёС‰РµРЅРЅРѕР№ СЃСЃС‹Р»РєРё:', error);
                
                // Fallback: РїСЂРѕР±СѓРµРј РїСЂСЏРјРѕРµ СЃРєР°С‡РёРІР°РЅРёРµ РёР· Storage
                if (mod.file_path) {
                    console.log('рџ”„ РџСЂРѕР±СѓРµРј РїСЂСЏРјРѕРµ СЃРєР°С‡РёРІР°РЅРёРµ РёР· Storage...');
                    
                    try {
                        const { data: { publicUrl } } = window.supabase.storage
                            .from('private-mods')
                            .getPublicUrl(mod.file_path);
                        
                        if (publicUrl) {
                            console.log('рџ“Ґ РџСЂСЏРјР°СЏ СЃСЃС‹Р»РєР° РЅР° Storage:', publicUrl);
                            window.location.href = publicUrl;
                            return;
                        }
                    } catch (storageError) {
                        console.error('вќЊ РћС€РёР±РєР° Storage:', storageError);
                    }
                }
                
                // Р•СЃР»Рё РµСЃС‚СЊ РІРЅРµС€РЅСЏСЏ СЃСЃС‹Р»РєР°, РёСЃРїРѕР»СЊР·СѓРµРј РµС‘
                if (mod.download_url) {
                    console.log('рџ“Ґ РСЃРїРѕР»СЊР·СѓРµРј РІРЅРµС€РЅСЋСЋ СЃСЃС‹Р»РєСѓ:', mod.download_url);
                    const link = document.createElement('a');
                    link.href = mod.download_url;
                    link.target = '_blank';
                    link.rel = 'noopener noreferrer';
                    document.body.appendChild(link);
                    link.click();
                    document.body.removeChild(link);
                } else {
                    showNotification('вќЊ РќРµ СѓРґР°Р»РѕСЃСЊ СЃРєР°С‡Р°С‚СЊ С„Р°Р№Р». РЎРІСЏР¶РёС‚РµСЃСЊ СЃ Р°РґРјРёРЅРёСЃС‚СЂР°С†РёРµР№.', 'error');
                }
            }
        } else {
            // --- Р›РћР“РРљРђ Р”Р›РЇ РџРЈР‘Р›РР§РќР«РҐ РњРћР”РћР’ ---
            console.log('рџ“Ѓ Р­С‚Рѕ РїСѓР±Р»РёС‡РЅС‹Р№ РјРѕРґ. РЎРєР°С‡РёРІР°РµРј РЅР°РїСЂСЏРјСѓСЋ.');
            // Р•СЃР»Рё РµСЃС‚СЊ download_url (РІРЅРµС€РЅСЏСЏ РёР»Рё РїСѓР±Р»РёС‡РЅР°СЏ), РёСЃРїРѕР»СЊР·СѓРµРј РµС‘
            if (mod.download_url) {
                window.open(mod.download_url, '_blank');
            } else if (mod.file_path) {
                // Р—Р°РїР°СЃРЅРѕР№ РІР°СЂРёР°РЅС‚: РіРµРЅРµСЂРёСЂСѓРµРј РїСѓР±Р»РёС‡РЅСѓСЋ СЃСЃС‹Р»РєСѓ РёР· file_path
                const { data: publicUrlData, error: urlError } = window.supabase.storage.from('site-assets').getPublicUrl(mod.file_path);

                if (urlError || !publicUrlData || !publicUrlData.publicUrl) {
                    throw new Error('РќРµ СѓРґР°Р»��ѕСЃС�� РїРѕР»СѓС��РёС‚СЊ РїСѓР��Р»Р��С‡РЅСѓСЋ СЃСЃС‹Р»РєСѓ РЅР° С„Р°Р№Р».');
                }

                window.open(publicUrlData.publicUrl, '_blank');
            } else {
                throw new Error('РЎСЃС‹Р»РєР° РЅР° С„Р°Р№Р» РЅРµ РЅР°Р№РґРµРЅР°.');
            }
        }
    } catch (error) {
        console.error('вќЊ [РЎРљРђР§РР’РђРќРР•] РћС€РёР±РєР° СЃРєР°С‡РёРІР°РЅРёСЏ РјРѕРґР°:', error);
        showNotification('РћС€РёР±РєР° СЃРєР°С‡РёРІР°РЅРёСЏ: ' + error.message, 'error');
    }
}

// Р¤СѓРЅРєС†РёСЏ showAdminPanel РїРµСЂРµРЅРµСЃРµРЅР° РІ admin-functions.js СЃ РїСЂРѕРІРµСЂРєРѕР№ РїР°СЂРѕР»СЏ

function createAdminOverlay() {
    const overlay = document.createElement('div');
    overlay.id = 'admin-panel-overlay';
    overlay.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        width: 100vw;
        height: 100vh;
        background: rgba(0, 0, 0, 0.5);
        z-index: 9999;
        opacity: 0;
        pointer-events: none;
    `;
    overlay.onclick = function(e) {
        // Р—Р°РєСЂС‹РІР°РµРј С‚РѕР»СЊРєРѕ РїСЂРё РєР»РёРєРµ РїРѕ overlay, Р° РЅРµ РїРѕ РїР°РЅРµР»Рё
        if (e.target === overlay) {
            hideAdminPanel();
        }
    };
    document.body.appendChild(overlay);
    return overlay;
}

/**
 * РџРµСЂРµРєР»СЋС‡Р°РµС‚ Р°РєС‚РёРІРЅСѓСЋ РІРµСЂСЃРёСЋ РёРіСЂС‹.
 * @param {string} gameVersion - Р’РµСЂСЃРёСЏ РёРіСЂС‹ ('fs25', 'fs22', 'fs19').
 */
function switchGameVersion(gameVersion, categoryId = 'Р’СЃРµ') {
    console.log(`рџЋ® РџРµСЂРµРєР»СЋС‡РµРЅРёРµ РЅР° РёРі��ЂСѓ: ${gameVersion}, РєР°С‚РµРіРѕСЂРёСЏ: ${categoryId}`);
    currentGameVersion = gameVersion;
    
    // РЎРѕС…СЂР°РЅСЏРµРј РІ localStorage
    if (typeof storageManager !== 'undefined' && typeof storageManager.setLocalStorage === 'function') {
        storageManager.setLocalStorage('selectedGameVersion', gameVersion);
    } else {
        localStorage.setItem('selectedGameVersion', gameVersion);
    }

    // вњ… РРЎРџР РђР’Р›Р•РќРР•: Р•СЃР»Рё РїРµСЂРµРєР»СЋС‡Р°РµРјСЃСЏ РјРµР¶РґСѓ РѕР±С‹С‡РЅС‹РјРё РёРіСЂР°РјРё, СЃР±СЂР°СЃС‹РІР°РµРј РєР°С‚РµРіРѕСЂРёСЋ РЅР° "Р’СЃРµ"
    if (!['vip_mods'].includes(gameVersion) && !['vip_mods'].includes(currentGameVersion)) {
        categoryId = 'Р’СЃРµ';
        console.log(`рџ”„ [РРЎРџР РђР’Р›Р•РќРР•] РЎР±СЂР°СЃС‹РІР°РµРј РєР°С‚РµРіРѕСЂРёСЋ РЅР° "Р’СЃРµ" РґР»СЏ РѕР±С‹С‡РЅРѕР№ РёРіСЂС‹: ${gameVersion}`);
    }

    // вњ… РРЎРџР РђР’Р›Р•РќРР•: Р¦РµРЅС‚СЂР°Р»РёР·СѓРµРј Р»РѕРіРёРєСѓ СЃРјРµРЅС‹ С†РІРµС‚Р° Р·РґРµСЃСЊ.
    const colorClassMap = {
        'fs25': 'fs25-category-color',
        'fs22': 'fs22-category-color',
        'fs19': 'fs19-category-color',
        'vip_mods': 'vip-category-color'
    };

    const colorClass = colorClassMap[gameVersion];

    // РћР±РЅРѕРІР»СЏРµРј Р°РєС‚РёРІРЅСѓСЋ РєРЅРѕРїРєСѓ РёРіСЂС‹
    document.querySelectorAll('.game-btn').forEach(btn => {
        const isActive = btn.dataset.game === gameVersion;
        btn.classList.toggle('active', isActive);
        if (isActive) {
            btn.classList.add(colorClass);
        } else {
            // РЈР±РёСЂР°РµРј РІСЃРµ С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ СЃ РЅРµР°РєС‚РёРІРЅС‹С… РєРЅРѕРїРѕРє
            btn.classList.remove('fs25-category-color', 'fs22-category-color', 'fs19-category-color', 'vip-category-color');
        }
    });

    // вњ… РќРћР’РћР•: РџСЂРёРјРµРЅСЏРµРј С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ Рє РєРѕРЅС‚РµР№РЅРµСЂР°Рј РєР°С‚РµРіРѕСЂРёР№
    document.querySelectorAll('.game-categories').forEach(container => {
        // РЈР±РёСЂР°РµРј РІСЃРµ С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹
        container.classList.remove('fs25-category-color', 'fs22-category-color', 'fs19-category-color', 'vip-category-color');
        
        // Р”РѕР±Р°РІР»СЏРµРј С†РІРµС‚РѕРІРѕР№ РєР»Р°СЃСЃ РµСЃР»Рё РєРѕРЅС‚РµР№РЅРµСЂ Р°РєС‚РёРІРµРЅ
        if (container.classList.contains('active')) {
            container.classList.add(colorClass);
        }
    });

    // вњ… РќРћР’РђРЇ Р›РћР“РРљРђ: РЈРїСЂР°РІР»СЏРµРј РІРёРґРёРјРѕСЃС‚СЊСЋ VIP РїР°РЅРµР»Рё
    const isVipGame = gameVersion === 'vip_mods';
    const vipCategories = document.querySelectorAll('[id^="vip_"]');
    const regularCategories = document.querySelectorAll('[id$="Categories"]:not([id^="vip_"])');
    
    // РЎРєСЂС‹РІР°РµРј РІСЃРµ VIP РєР°С‚РµРіРѕСЂРёРё РїСЂРё РІС‹Р±РѕСЂРµ РѕР±С‹С‡РЅРѕР№ РёРіСЂС‹
    if (!isVipGame) {
        vipCategories.forEach(catBlock => {
            catBlock.classList.remove('active');
            // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РЇРІРЅРѕ СЃРєСЂС‹РІР°РµРј VIP РєР°С‚РµРіРѕСЂРёРё С‡РµСЂРµР· display
            catBlock.style.display = 'none';
            // РЈР±РёСЂР°РµРј С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ СЃ VIP РєРѕРЅС‚РµР№РЅРµСЂРѕРІ
            catBlock.classList.remove('fs25-category-color', 'fs22-category-color', 'fs19-category-color', 'vip-category-color');
        });
        
        // РџРѕРєР°Р·С‹РІР°РµРј С‚РѕР»СЊРєРѕ РѕР±С‹С‡РЅС‹Рµ РєР°С‚РµРіРѕСЂРёРё
        regularCategories.forEach(catBlock => {
            const isActive = catBlock.id === `${gameVersion}Categories`;
            catBlock.classList.toggle('active', isActive);
            
            // РџСЂРёРјРµРЅСЏРµРј С†РІРµС‚РѕРІРѕР№ РєР»Р°СЃСЃ Рє Р°РєС‚РёРІРЅРѕРјСѓ РєРѕРЅС‚РµР№РЅРµСЂСѓ
            if (isActive) {
                catBlock.classList.add(colorClass);
            } else {
                // РЈР±РёСЂР°РµРј С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ СЃ РЅРµР°РєС‚РёРІРЅС‹С… РєРѕРЅС‚РµР№РЅРµСЂРѕРІ
                catBlock.classList.remove('fs25-category-color', 'fs22-category-color', 'fs19-category-color', 'vip-category-color');
            }
        });
    } else {
        // РЎРєСЂС‹РІР°РµРј РѕР±С‹С‡РЅС‹Рµ РєР°С‚РµРіРѕСЂРёРё РїСЂРё РІС‹Р±РѕСЂРµ VIP
        regularCategories.forEach(catBlock => {
            catBlock.classList.remove('active');
            // РЈР±РёСЂР°РµРј С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ СЃ РѕР±С‹С‡РЅС‹С… РєРѕРЅС‚РµР№РЅРµСЂРѕРІ
            catBlock.classList.remove('fs25-category-color', 'fs22-category-color', 'fs19-category-color', 'vip-category-color');
        });
        
        // РџРѕРєР°Р·С‹РІР°РµРј VIP РєР°С‚РµРіРѕСЂРёРё
        vipCategories.forEach(catBlock => {
            const isActive = catBlock.id === `${gameVersion}Categories`;
            catBlock.classList.toggle('active', isActive);
            
            // рџ”§ РРЎРџР РђР’Р›Р•РќРР•: РЇРІРЅРѕ РїРѕРєР°Р·С‹РІР°РµРј VIP РєР°С‚РµРіРѕСЂРёРё С‡РµСЂРµР· display
            if (isActive) {
                catBlock.style.display = 'block';
            } else {
                catBlock.style.display = 'none';
            }
            
            // РџСЂРёРјРµРЅСЏРµРј VIP С†РІРµС‚РѕРІРѕР№ РєР»Р°СЃСЃ Рє Р°РєС‚РёРІРЅРѕРјСѓ VIP РєРѕРЅС‚РµР№РЅРµСЂСѓ
            if (isActive) {
                catBlock.classList.add(colorClass);
            } else {
                // РЈР±РёСЂР°РµРј С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ СЃ РЅРµР°РєС‚РёРІРЅС‹С… VIP РєРѕРЅС‚РµР№РЅРµСЂРѕРІ
                catBlock.classList.remove('fs25-category-color', 'fs22-category-color', 'fs19-category-color', 'vip-category-color');
            }
        });
    }

    // РЎР±СЂР°СЃС‹РІР°РµРј Р°РєС‚РёРІРЅСѓСЋ РєР°С‚РµРіРѕСЂРёСЋ РЅР° "Р’СЃРµ РјРѕРґС‹" Рё Р·Р°РіСЂСѓР¶Р°РµРј РёС…
    loadModsByCategory(categoryId, gameVersion);

    // РћР±РЅРѕРІР»СЏРµРј С†РІРµС‚Р° Р·Р°РіРѕР»РѕРІРєРѕРІ
    updateCategoryTitles(gameVersion);

    // Р—Р°РіСЂСѓР¶Р°РµРј СЃС‡РµС‚С‡РёРєРё РјРѕРґРѕРІ РґР»СЏ РЅРѕРІРѕР№ РёРіСЂС‹
    loadCategoriesModCount(gameVersion);

    // рџЋЁ Р¤РРќРђР›Р¬РќРћР• РџР РРњР•РќР•РќРР•: РЈР±РµРґРёРјСЃСЏ С‡С‚Рѕ С†РІРµС‚Р° РїСЂРёРјРµРЅРµРЅС‹ РїРѕСЃР»Рµ РІСЃРµС… РѕРїРµСЂР°С†РёР№
    setTimeout(() => {
        applyCategoryColors();
    }, 300);

    // рџ”Ґ РЈРЎРўРђРќРђР’Р›РР’РђР•Рњ РђРўР РР‘РЈРў РђРљРўРР’РќРћР™ РР“Р Р« Р”Р›РЇ CSS РЎРўРР›Р•Р™
    document.body.setAttribute('data-active-game', gameVersion);

    console.log(`вњ… РџРµСЂРµРєР»СЋС‡РµРЅРѕ РЅР° РёРіСЂСѓ: ${gameVersion}, VIP СЂРµР¶РёРј: ${isVipGame}, РєР°С‚РµРіРѕСЂРёСЏ: ${categoryId}`);
}

/**
 * РџСЂРёРјРµРЅСЏРµС‚ С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹ Рє Р°РєС‚РёРІРЅС‹Рј РєРѕРЅС‚РµР№РЅРµСЂР°Рј РєР°С‚РµРіРѕСЂРёР№
 * Р’С‹Р·С‹РІР°РµС‚СЃСЏ РїСЂРё Р·Р°РіСЂСѓР·РєРµ СЃС‚СЂР°РЅРёС†С‹ Рё РїРµСЂРµРєР»СЋС‡РµРЅРёРё РёРіСЂ
 */
function applyCategoryColors() {
    const activeContainer = document.querySelector('.game-categories.active');
    if (!activeContainer) return;
    
    // РћРїСЂРµРґРµР»СЏРµРј С‚РёРї РєРѕРЅС‚РµР№РЅРµСЂР° РїРѕ ID
    let gameVersion = 'fs25'; // РїРѕ СѓРјРѕР»С‡Р°РЅРёСЋ
    
    if (activeContainer.id === 'vip_modsCategories') {
        gameVersion = 'vip_mods';
    } else if (activeContainer.id === 'fs25Categories') {
        gameVersion = 'fs25';
    } else if (activeContainer.id === 'fs22Categories') {
        gameVersion = 'fs22';
    } else if (activeContainer.id === 'fs19Categories') {
        gameVersion = 'fs19';
    }
    
    // рџ”Ґ РџР РРњР•РќРЇР•Рњ РРќР›РђР™Рќ РЎРўРР›Р РќРђРџР РЇРњРЈР® Р”Р›РЇ РњРђРљРЎРРњРђР›Р¬РќРћР™ РќРђР”Р•Р–РќРћРЎРўР
    const colorStyles = {
        'fs25': {
            background: 'linear-gradient(135deg, rgba(76, 175, 80, 0.25), rgba(102, 187, 106, 0.3))',
            border: '2px solid rgba(76, 175, 80, 0.5)',
            borderRadius: '12px',
            boxShadow: '0 4px 25px rgba(76, 175, 80, 0.4)',
            padding: '10px',
            margin: '5px 0'
        },
        'fs22': {
            background: 'linear-gradient(135deg, rgba(33, 150, 243, 0.25), rgba(100, 181, 246, 0.3))',
            border: '2px solid rgba(33, 150, 243, 0.5)',
            borderRadius: '12px',
            boxShadow: '0 4px 25px rgba(33, 150, 243, 0.4)',
            padding: '10px',
            margin: '5px 0'
        },
        'fs19': {
            background: 'linear-gradient(135deg, rgba(255, 193, 7, 0.25), rgba(255, 213, 79, 0.3))',
            border: '2px solid rgba(255, 193, 7, 0.5)',
            borderRadius: '12px',
            boxShadow: '0 4px 25px rgba(255, 193, 7, 0.4)',
            padding: '10px',
            margin: '5px 0'
        },
        'vip_mods': {
            background: 'linear-gradient(135deg, rgba(255, 215, 0, 0.25), rgba(255, 140, 0, 0.3), rgba(244, 67, 54, 0.2))',
            backgroundSize: '250% 250%',
            border: '2px solid rgba(255, 215, 0, 0.6)',
            borderRadius: '12px',
            boxShadow: '0 4px 30px rgba(255, 215, 0, 0.5)',
            padding: '10px',
            margin: '5px 0'
        }
    };
    
    const styles = colorStyles[gameVersion];
    
    // рџ”Ґ РџР РРњР•РќРЇР•Рњ РРќР›РђР™Рќ РЎРўРР›Р РЎР РђР—РЈ
    Object.assign(activeContainer.style, styles);
    
    // рџЋЁ Р”РћР‘РђР’Р›РЇР•Рњ РљР›РђРЎРЎР« Р”Р›РЇ Р”РћРџРћР›РќРРўР•Р›Р¬РќРћР™ РЎРўРР›РР—РђР¦РР
    const colorClassMap = {
        'fs25': 'fs25-category-color',
        'fs22': 'fs22-category-color',
        'fs19': 'fs19-category-color',
        'vip_mods': 'vip-category-color'
    };
    
    // РЈРґР°Р»СЏРµРј РІСЃРµ С†РІРµС‚РѕРІС‹Рµ РєР»Р°СЃСЃС‹
    activeContainer.classList.remove('fs25-category-color', 'fs22-category-color', 'fs19-category-color', 'vip-category-color');
    
    // Р”РѕР±Р°РІР»СЏРµРј РЅСѓР¶РЅС‹Р№ РєР»Р°СЃСЃ
    activeContainer.classList.add(colorClassMap[gameVersion]);
    
    // console.log(`рџЋЁ РџСЂРёРјРµРЅРµРЅ С†РІРµС‚ ${colorClassMap[gameVersion]} Рє РєРѕРЅС‚РµР№РЅРµСЂСѓ ${activeContainer.id} СЃ РёРЅР»Р°Р№РЅ СЃС‚РёР»СЏРјРё`);
    
    // рџ”Ґ РџРћР’РўРћР РќРћР• РџР РРњР•РќР•РќРР• Р§Р•Р Р•Р— 100РњРЎ Р”Р›РЇ РќРђР”Р•Р–РќРћРЎРўР
    setTimeout(() => {
        Object.assign(activeContainer.style, styles);
        activeContainer.classList.add(colorClassMap[gameVersion]);
    }, 100);
}

/**
 * Р—Р°РіСЂСѓР¶Р°РµС‚ РјРѕРґС‹ РґР»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ РєР°С‚РµРіРѕСЂРёРё Рё РёРіСЂС‹ (Р°Р»СЊС‚РµСЂРЅР°С‚РёРІРЅР°СЏ СЂРµР°Р»РёР·Р°С†РёСЏ).
 * @param {string} categoryId - ID РєР°С‚РµРіРѕСЂРёРё ('Р’СЃРµ', 'maps', 'tractors', etc.).
 * @param {string} gameVersion - Р’РµСЂСЃРёСЏ РёРіСЂС‹.
 */
async function loadModsByCategoryAlt(categoryId, gameVersion) {
    console.log(`рџ”„ Р—Р°РіСЂСѓР·РєР° РјРѕРґРѕРІ РґР»СЏ РєР°С‚РµРіРѕСЂРёРё: ${categoryId}, РёРіСЂР°: ${gameVersion}`);
    
    // Р”РµС‚Р°Р»СЊРЅР°СЏ РѕС‚Р»Р°РґРєР° РґР»СЏ VIP СЂР°Р·РґРµР»РѕРІ
    if (gameVersion === 'vip_mods') {
        console.log('рџ’Ћ VIP СЂРµР¶РёРј:');
        console.log('  - categoryId (РІРµСЂСЃРёСЏ РёРіСЂС‹):', categoryId);
        console.log('  - gameVersion:', gameVersion);
    }
    
    // Р”РµС‚Р°Р»СЊРЅР°СЏ РѕС‚Р»Р°РґРєР° РґР»СЏ VIP СЂР°Р·РґРµР»РѕРІ
    if (gameVersion === 'vip_mods') {
        console.log('рџ’Ћ VIP СЂРµР¶РёРј:');
        console.log('  - categoryId (РІРµСЂСЃРёСЏ РёРіСЂС‹):', categoryId);
        console.log('  - gameVersion:', gameVersion);
    }

    // РџСЂРѕРІРµСЂРєР° РґРѕСЃС‚СѓРїР° Рє VIP-РјРѕРґР°Рј
    if (categoryId === 'vip_mods') {
        console.log('рџ’Ћ Р—Р°РїСЂРѕС€РµРЅР° РєР°С‚РµРіРѕСЂРёСЏ VIP-РјРѕРґРѕРІ. РџСЂРѕРІРµСЂСЏРµРј РґРѕСЃС‚СѓРї...');
        const profile = await getUserRole(true);
        const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
        const hasVipAccess = profile && (profile.is_vip === true || vipRoles.includes(profile.role) || profile.is_owner === true);

        if (!hasVipAccess) {
            console.warn('вќЊ Р”РѕСЃС‚СѓРї Рє VIP-РјРѕРґР°Рј Р·Р°РїСЂРµС‰РµРЅ РґР»СЏ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ СЃ СЂРѕР»СЊСЋ:', profile?.role);
            // РЈР‘Р РђР›Р РЎРћРћР‘Р©Р•РќРР• - РЅРµ РїРѕРєР°Р·С‹РІР°РµРј СѓРІРµРґРѕРјР»РµРЅРёРµ РїРѕР»СЊР·РѕРІР°С‚РµР»СЋ
            // showNotification('вќЊ РЈ РІР°СЃ РЅРµС‚ РґРѕСЃС‚СѓРїР° Рє VIP-РјРѕРґР°Рј.', 'error');
            const modsContainer = document.getElementById('modsContainer');
            if (modsContainer) {
                modsContainer.innerHTML = '<div class="no-mods" style="color: #f44336; text-align: center; padding: 2rem;">рџљ« Р”РѕСЃС‚СѓРї Рє СЌС‚РѕР№ РєР°С‚РµРіРѕСЂРёРё Р·Р°РїСЂРµС‰РµРЅ.</div>';
            }
            // РЎРЅРёРјР°РµРј Р°РєС‚РёРІРЅРѕСЃС‚СЊ СЃ РєРЅРѕРїРєРё VIP, РµСЃР»Рё РґРѕСЃС‚СѓРї Р·Р°РїСЂРµС‰РµРЅ
            const vipBtn = document.querySelector(`.category-btn[data-category-id="vip_mods"]`);
            if (vipBtn) vipBtn.classList.remove('active');
            return;
        }
        console.log('вњ… Р”РѕСЃС‚СѓРї Рє VIP-РјРѕРґР°Рј СЂР°Р·СЂРµС€РµРЅ.');
    }

    // РћР±РЅРѕРІР»СЏРµРј Р°РєС‚РёРІРЅРѕРµ СЃРѕСЃС‚РѕСЏРЅРёРµ РєРЅРѕРїРѕРє РєР°С‚РµРіРѕСЂРёР№
    updateCategoryStates(categoryId, gameVersion);

    // Р—Р°РіСЂСѓР¶Р°РµРј РјРѕРґС‹
    await loadModsDirectly(categoryId, gameVersion);
}

/**
 * РџРѕРєР°Р·С‹РІР°РµС‚ РєР°С‚РµРіРѕСЂРёРё РґР»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ РёРіСЂС‹.
 * @param {string} gameVersion - Р’РµСЂСЃРёСЏ РёРіСЂС‹.
 */
function showGameCategories(gameVersion) {
    console.log(`рџ“‚ РџРѕРєР°Р·С‹РІР°РµРј РєР°С‚РµРіРѕСЂРёРё РґР»СЏ РёРіСЂС‹: ${gameVersion}`);
    
    // вњ… РќРћР’РђРЇ Р›РћР“РРљРђ: РЈРїСЂР°РІР»СЏРµРј РІРёРґРёРјРѕСЃС‚СЊСЋ VIP РїР°РЅРµР»Рё
    const isVipGame = gameVersion === 'vip_mods';
    const vipCategories = document.querySelectorAll('[id^="vip_"]');
    const regularCategories = document.querySelectorAll('[id$="Categories"]:not([id^="vip_"])');
    
    // РЎРєСЂС‹РІР°РµРј РІСЃРµ РєР°С‚РµРіРѕСЂРёРё СЃРЅР°С‡Р°Р»Р°
    document.querySelectorAll('.game-categories').forEach(categories => {
        categories.classList.remove('active');
    });
    
    if (!isVipGame) {
        // РЎРєСЂС‹РІР°РµРј РІСЃРµ VIP РєР°С‚РµРіРѕСЂРёРё РїСЂРё РІС‹Р±РѕСЂРµ РѕР±С‹С‡РЅРѕР№ РёРіСЂС‹
        vipCategories.forEach(catBlock => {
            catBlock.classList.remove('active');
        });
        
        // РџРѕРєР°Р·С‹РІР°РµРј С‚РѕР»СЊРєРѕ РѕР±С‹С‡РЅС‹Рµ РєР°С‚РµРіРѕСЂРёРё РґР»СЏ РІС‹Р±СЂР°РЅРЅРѕР№ РёРіСЂС‹
        const targetCategories = document.getElementById(`${gameVersion}Categories`);
        if (targetCategories) {
            targetCategories.classList.add('active');
            console.log(`рџ“‚ РџРѕРєР°Р·Р°РЅС‹ РѕР±С‹С‡РЅС‹Рµ РєР°С‚РµРіРѕСЂРёРё РґР»СЏ: ${gameVersion}`);
        } else {
            console.error(`РћР±С‹С‡РЅС‹Рµ РєР°С‚РµРіРѕСЂРёРё РґР»СЏ РёРіСЂС‹ РЅРµ РЅР°Р№РґРµРЅС‹: ${gameVersion}`);
        }
    } else {
        // РЎРєСЂС‹РІР°РµРј РѕР±С‹С‡РЅС‹Рµ РєР°С‚РµРіРѕСЂРёРё РїСЂРё РІС‹Р±РѕСЂРµ VIP
        regularCategories.forEach(catBlock => {
            catBlock.classList.remove('active');
        });
        
        // РџРѕРєР°Р·С‹РІР°РµРј VIP РєР°С‚РµРіРѕСЂРёРё
        const targetCategories = document.getElementById(`${gameVersion}Categories`);
        if (targetCategories) {
            targetCategories.classList.add('active');
            // console.log(`рџ“‚ РџРѕРєР°Р·Р°РЅС‹ VIP РєР°С‚РµРіРѕСЂРёРё РґР»СЏ: ${gameVersion}`);
        } else {
            // console.error(`VIP РєР°С‚РµРіРѕСЂРёРё РЅРµ РЅР°Р№РґРµРЅС‹: ${gameVersion}`);
        }
    }
}

