/**
 * Р—Р°РіСЂСѓР¶Р°РµС‚ СЃРїРёСЃРѕРє Р°РґРјРёРЅРёСЃС‚СЂР°С‚РѕСЂРѕРІ РґР»СЏ РїРµСЂРµРґР°С‡Рё РјРѕРґРѕРІ
 */
async function loadAdminsForTransfer() {
    try {
        const { data: admins, error } = await supabase
            .from('profiles')
            .select('id, username, role')
            .in('role', ['owner', 'admin_senior', 'admin'])
            .neq('id', getCurrentUser()?.id || '')
            .order('role', { ascending: false });

        if (error) throw error;

        const select = document.getElementById('transferTarget');
        if (select) {
            select.innerHTML = '<option value="">Р’С‹Р±РµСЂРёС‚Рµ Р°РґРјРёРЅРёСЃС‚СЂР°С‚РѕСЂР°...</option>';
            
            if (admins && admins.length > 0) {
                admins.forEach(admin => {
                    const option = document.createElement('option');
                    option.value = admin.id;
                    option.textContent = `${getRoleName(admin.role)} - ${admin.username}`;
                    select.appendChild(option);
                });
            } else {
                select.innerHTML = '<option value="">РќРµС‚ РґРѕСЃС‚СѓРїРЅС‹С… Р°РґРјРёРЅРёСЃС‚СЂР°С‚РѕСЂРѕРІ</option>';
            }
        }
    } catch (error) {
        console.error('вќЊ РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё Р°РґРјРёРЅРёСЃС‚СЂР°С‚РѕСЂРѕРІ:', error);
        const select = document.getElementById('transferTarget');
        if (select) {
            select.innerHTML = '<option value="">РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё</option>';
        }
    }
}

/**
 * Р’С‹РїРѕР»РЅСЏРµС‚ Р±РµР·РѕРїР°СЃРЅРѕРµ СѓРґР°Р»РµРЅРёРµ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
 */
async function executeSafeDeleteUser(userId, username, currentRole) {
    const password = document.getElementById('deletePassword').value;
    const modsAction = document.getElementById('modsAction').value;
    const transferTarget = document.getElementById('transferTarget').value;
    const deleteProfile = document.getElementById('deleteProfile').checked;
    const deleteAuth = document.getElementById('deleteAuth').checked;
    const createLog = document.getElementById('createLog').checked;

    // РџСЂРѕРІРµСЂСЏРµРј СЃРїРµС†-РїР°СЂРѕР»СЊ
    if (password !== OWNER_TRANSFER_PASSWORD + '_DELETE') {
        showNotification('вќЊ РќРµРІРµСЂРЅС‹Р№ СЃРїРµС†-РїР°СЂРѕР»СЊ РґР»СЏ СѓРґР°Р»РµРЅРёСЏ!', 'error');
        return;
    }

    // РџСЂРѕРІРµСЂСЏРµРј СѓСЃР»РѕРІРёСЏ
    if (modsAction === 'transfer' && !transferTarget) {
        showNotification('вќЊ Р’С‹Р±РµСЂРёС‚Р�� РїРѕР»СѓС‡��°��‚РµР»СЏ РґР»СЏ РїРµСЂРµРґР°С‡Рё РјРѕРґРѕРІ!', 'error');
        return;
    }

    if (!confirm(`вљ пёЏ Р’РќРРњРђРќРР•! Р’С‹ СЃРѕР±РёСЂР°РµС‚РµСЃСЊ РїРѕР»РЅРѕСЃС‚СЊСЋ СѓРґР°Р»РёС‚СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ ${username}!\n\nР­С‚Р° РѕРїРµСЂР°С†РёСЏ РЅРµРѕР±СЂР°С‚РёРјР°. Р’СЃРµ РґР°РЅРЅС‹Рµ Р±СѓРґСѓС‚ СѓРґР°Р»РµРЅС‹ РёР»Рё РїРµСЂРµРґР°РЅС‹ РІ СЃРѕРѕС‚РІРµС‚СЃС‚РІРёРё СЃ РІС‹Р±СЂР°РЅРЅС‹РјРё РїР°СЂР°РјРµС‚СЂР°РјРё.`)) {
        return;
    }

    try {
        showNotification('вЏі РќР°С‡РёРЅР°СЋ Р±РµР·РѕРїР°СЃРЅРѕРµ СѓРґР°Р»РµРЅРёРµ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ...', 'info');

        // 1. РћР±СЂР°Р±Р°С‚С‹РІР°РµРј РјРѕРґС‹ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
        const { data: userMods, error: modsError } = await supabase
            .from('mods')
            .select('id, title')
            .eq('author_id', userId);

        if (modsError) throw modsError;

        let modsTransferred = 0;
        let modsDeleted = 0;

        if (userMods && userMods.length > 0) {
            if (modsAction === 'transfer' && transferTarget) {
                // РџРѕР��СѓС‡Р°РµРј РґР°РЅРЅС‹Рµ РїР��Р»Сѓ��‡Р°С‚РµР»СЏ
                const { data: targetUser, error: targetError } = await supabase
                    .from('profiles')
                    .select('username')
                    .eq('id', transferTarget)
                    .single();

                if (!targetError && targetUser) {
                    // РџРµСЂРµРґР°РµРј РјРѕРґС‹ РґСЂСѓРіРѕРјСѓ Р°РґРјРёРЅРёСЃС‚СЂР°С‚РѕСЂСѓ
                    const { error: transferError } = await supabase
                        .from('mods')
                        .update({
                            author_id: transferTarget,
                            author_name: targetUser.username,
                            updated_at: new Date().toISOString()
                        })
                        .eq('author_id', userId);

                    if (transferError) throw transferError;
                    modsTransferred = userMods.length;
                }
            } else if (modsAction === 'system') {
                // РџРµСЂРµРґР°РµРј РјРѕРґС‹ СЃРёСЃС‚РµРјРЅРѕРјСѓ РїРѕР»СЊР·РѕРІР°С‚РµР»СЋ
                const { error: systemError } = await supabase
                    .from('mods')
                    .update({
                        author_id: '00000000-0000-0000-0000-000000000000',
                        author_name: 'РЎРёСЃС‚РµРјР° KEROSMODS',
                        updated_at: new Date().toISOString()
                    })
                    .eq('author_id', userId);

                if (systemError) throw systemError;
                modsTransferred = userMods.length;
            } else if (modsAction === 'delete') {
                // РЈРґР°Р»СЏРµРј РјРѕРґС‹
                const { error: deleteModsError } = await supabase
                    .from('mods')
                    .delete()
                    .eq('author_id', userId);

                if (deleteModsError) throw deleteModsError;
                modsDeleted = userMods.length;
            }
        }

        // 2. РЈРґР°Р»СЏРµРј РїСЂРѕС„РёР»СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
        if (deleteProfile) {
            const { error: profileError } = await supabase
                .from('profiles')
                .delete()
                .eq('id', userId);

            if (profileError) throw profileError;
        }

        // 3. РЈРґР°Р»СЏРµРј РґР°РЅРЅС‹Рµ Р°СѓС‚РµРЅС‚РёС„РёРєР°С†РёРё (РµСЃР»Рё РµСЃС‚СЊ РґРѕСЃС‚СѓРї)
        if (deleteAuth) {
            try {
                // РџРѕРїС‹С‚РєР° СѓРґР°Р»РёС‚СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РёР· auth.users (С‚СЂРµР±СѓРµС‚ admin rights)
                const { error: authError } = await supabase.auth.admin.deleteUser(userId);
                if (authError && authError.message !== 'User not found') {
                    console.warn('вљ пёЏ РќРµ СѓРґР°Р»РѕСЃСЊ СѓРґР°Р»РёС‚СЊ auth РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', authError);
                }
            } catch (authError) {
                console.warn('вљ пёЏ РќРµ СѓРґР°Р»РѕСЃСЊ СѓРґР°Р»РёС‚СЊ auth РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ (РІРѕР·РјРѕР¶РЅРѕ, РЅРµРґРѕСЃС‚Р°С‚РѕС‡РЅРѕ РїСЂР°РІ):', authError);
            }
        }

        // 4. РЎРѕР·РґР°РµРј Р·Р°РїРёСЃСЊ РІ Р»РѕРіРµ
        if (createLog) {
            const { error: logError } = await supabase
                .from('user_deletion_log')
                .insert({
                    deleted_user_id: userId,
                    deleted_username: username,
                    deleted_role: currentRole,
                    deleted_by: getCurrentUser()?.id,
                    deletion_date: new Date().toISOString(),
                    mods_action: modsAction,
                    mods_transferred: modsTransferred,
                    mods_deleted: modsDeleted,
                    transfer_target: transferTarget || null
                });

            if (logError) {
                console.warn('вљ пёЏ РќРµ СѓРґР°Р»РѕСЃСЊ СЃРѕР·РґР°С‚СЊ Р·Р°РїРёСЃСЊ РІ Р»РѕРіРµ:', logError);
            }
        }

        // Р—Р°РєСЂС‹РІР°РµРј РјРѕРґР°Р»СЊРЅРѕРµ РѕРєРЅРѕ
        document.querySelector('.safe-delete-modal')?.remove();

        // РџРѕРєР°Р·С‹РІР°РµРј СЂРµР·СѓР»СЊС‚Р°С‚
        let resultMessage = `вњ… РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ ${username} СѓСЃРїРµС€РЅРѕ СѓРґР°Р»РµРЅ!\n\n`;
        if (modsTransferred > 0) {
            resultMessage += `рџ“¦ РџРµСЂРµРґР°РЅРѕ РјРѕРґРѕРІ: ${modsTransferred}\n`;
        }
        if (modsDeleted > 0) {
            resultMessage += `рџ—‘пёЏ РЈРґР°Р»РµРЅРѕ РјРѕРґРѕРІ: ${modsDeleted}\n`;
        }

        showNotification(resultMessage, 'success');

        // РћР±РЅРѕРІР»СЏРµРј СЃРїРёСЃРѕРє
        await loadAdminList();
        await updateUsersStatistics();

    } catch (error) {
        console.error('вќЊ РћС€РёР±РєР° Р±РµР·РѕРїР°СЃРЅРѕРіРѕ СѓРґР°Р»РµРЅРёСЏ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', error);
        showNotification(`вќЊ РћС€РёР±РєР° СѓРґР°Р»РµРЅРёСЏ: ${error.message}`, 'error');
    }
}

// Р”РѕР±Р°РІР»СЏРµРј РѕСЃС‚Р°Р»СЊРЅС‹Рµ С„СѓРЅРєС†РёРё РІ РіР»РѕР±Р°Р»СЊРЅСѓСЋ РѕР±Р»Р°СЃС‚СЊ
window.loadAdminList = loadAdminList;
window.showAdminRoleModal = showAdminRoleModal;
window.changeAdminRole = changeAdminRole;
window.showSafeDeleteUserModal = showSafeDeleteUserModal;
window.executeSafeDeleteUser = executeSafeDeleteUser;
window.loadAdminsForTransfer = loadAdminsForTransfer;

