    // Р°РЅР°Р»РѕРіРёС‡РЅРѕ РєР°Рє СЃРµР№С‡Р°СЃ Р·Р°РіСЂСѓР¶Р°СЋС‚СЃСЏ РјРѕРґС‹.
    console.log('РџРѕРїС‹С‚РєР° РѕС‚РєСЂС‹С‚СЊ СЂР°Р·РґРµР» "РўРѕРІР°СЂС‹".');
