        await updateUsersStatistics();
        
        // Р—Р°РїСѓСЃРєР°РµРј РѕР±РЅРѕРІР»РµРЅРёРµ СЃС‚Р°С‚РёСЃС‚РёРєРё Р°РєС‚РёРІРЅРѕСЃС‚Рё
