// РћСЃС‚Р°РЅРѕРІРєР° РѕР±РЅРѕРІР»РµРЅРёСЏ РїСЂРё Р·Р°РєСЂС‹С‚РёРё Р°РґРјРёРЅ РїР°РЅРµР»Рё
function stopActivityStatsUpdate() {
    if (activityStatsInterval) {
        clearInterval(activityStatsInterval);
        activityStatsInterval = null;
        console.log('рџ›‘ [stopActivityStatsUpdate] РћР±РЅРѕРІР»РµРЅРёРµ СЃС‚Р°С‚РёСЃС‚РёРєРё Р°РєС‚РёРІРЅРѕСЃС‚Рё РѕСЃС‚Р°РЅРѕРІР»РµРЅРѕ');
    }
}

// РћС‚СЃР»РµР¶РёРІР°РЅРёРµ Р°РєС‚РёРІРЅРѕСЃС‚Рё С‚РµРєСѓС‰РµРіРѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
function startActivityTracking() {
    if (!window.supabase) return;
    
    window.activityTracker = {
        lastActivity: Date.now(),
        lastUpdate: 0, // Р’СЂРµРјСЏ РїРѕСЃР»РµРґРЅРµРіРѕ РѕР±РЅРѕРІР»РµРЅРёСЏ
        events: ['mousedown', 'mousemove', 'keypress', 'keydown', 'keyup', 'scroll', 'click', 'touchstart', 'touchmove'],
        
        start() {
            if (this.isActive) return;
            
            this.isActive = true;
            this.lastActivity = Date.now();
            
            // РћР±РЅРѕРІР»СЏРµРј РєР°Р¶РґС‹Рµ 30 СЃРµРєСѓРЅРґ РґР»СЏ С‚РѕС‡РЅРѕРіРѕ РѕС‚СЃР»РµР¶РёРІР°РЅРёСЏ
            this.interval = setInterval(() => {
                this.checkStatus();
            }, 30000);
            
            // Р”РѕР±Р°РІР»СЏРµРј РѕР±СЂР°Р±РѕС‚С‡РёРєРё СЃРѕР±С‹С‚РёР№
            this.events.forEach(event => {
                document.addEventListener(event, () => {
                    this.lastActivity = Date.now();
                });
            });
        },
        
        checkStatus() {
            const now = Date.now();
            if (now - this.lastUpdate >= 30000) { // 30 СЃРµРєСѓРЅРґ
                this.lastUpdate = now;
                this.updateLastSeen();
            }
        },
        
        updateLastSeen() {
            try {
                const { data, error } = window.supabase.auth.getUser();
                if (error) {
                    console.warn('вљ пёЏ [SCRIPT.JS] РћС€РёР±РєР° РїРѕР»СѓС‡РµРЅРёСЏ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РІ updateLastSeen:', error.message);
                    return;
                }
                const user = data?.user;
                if (user) {
                    window.supabase
                        .from('profiles')
                        .update({ last_seen: new Date().toISOString() })
                        .eq('id', user.id)
                        .then(() => {
                            console.log('вњ… [SCRIPT.JS] last_seen РѕР±РЅРѕРІР»РµРЅ');
                        })
                        .catch(error => {
                            console.error('вќЊ [SCRIPT.JS] РћС€РёР±РєР° РѕР±РЅРѕРІР»РµРЅРёСЏ last_seen:', error);
                        });
                }
            } catch (error) {
                console.error('вќЊ [SCRIPT.JS] РћС€РёР±РєР° РІ updateLastSeen:', error);
            }
        }
    };
    
    window.activityTracker.start();
}

// Р—Р°РїСѓСЃРєР°РµРј РѕС‚СЃР»РµР¶РёРІР°РЅРёРµ Р°РєС‚РёРІРЅРѕСЃС‚Рё РїСЂРё Р·Р°РіСЂСѓР·РєРµ СЃС‚СЂР°РЅРёС†С‹
