// РџРѕРёСЃРє РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РґР»СЏ РІС‹РґР°С‡Рё VIP
window.searchUserForVip = async function() {
    const email = document.getElementById('vipUserEmailInput').value.trim().toLowerCase();
    
    if (!email) {
        showNotification('вќЊ Р’РІРµРґРёС‚Рµ email РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ', 'error', 3000);
        return;
    }

    try {
        const { data: user, error } = await supabase
            .from('profiles')
            .select('id, username, email, role, is_vip, vip_expires_at')
            .eq('email', email)
            .single();

        if (error || !user) {
            showNotification('вќЊ РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ СЃ С‚Р°РєРёРј email РЅРµ РЅР°Р№РґРµРЅ', 'error', 3000);
            return;
        }

        // РџРѕРєР°Р·С‹РІР°РµРј РёРЅС„РѕСЂРјР°С†РёСЋ Рѕ РїРѕР»СЊР·РѕРІР°С‚РµР»Рµ
        const userInfoDiv = document.getElementById('vip-user-info');
        const userDetailsDiv = document.getElementById('vip-user-details');
        
        if (user.is_vip || user.role === 'vip') {
            userDetailsDiv.innerHTML = `
                <div style="color: #ffd700 !important;">рџ’Ћ ${user.username || user.email}</div>
                <div style="color: #ff9800 !important; margin-top: 5px;">вљ пёЏ РЈР¶Рµ РёРјРµРµС‚ VIP СЃС‚Р°С‚СѓСЃ</div>
            `;
            userInfoDiv.style.display = 'block';
            userInfoDiv.style.background = 'rgba(255, 152, 0, 0.1)';
            userInfoDiv.style.borderColor = 'rgba(255, 152, 0, 0.3)';
            document.getElementById('confirmVipBtn').style.display = 'none';
        } else {
            userDetailsDiv.innerHTML = `
                <div style="color: #00ff41 !important;">рџ’Ћ ${user.username || user.email}</div>
                <div style="color: #ccc !important; margin-top: 5px;">рџ“§ ${user.email}</div>
                <div style="color: #2196F3 !important; margin-top: 5px;">рџЋ­ Р РѕР»СЊ: ${user.role || 'user'}</div>
            `;
            userInfoDiv.style.display = 'block';
            userInfoDiv.style.background = 'rgba(0, 255, 65, 0.1)';
            userInfoDiv.style.borderColor = 'rgba(0, 255, 65, 0.3)';
            document.getElementById('confirmVipBtn').style.display = 'block';
            
            // РЎРѕС…СЂР°РЅСЏРµРј ID РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РґР»СЏ РїРѕСЃР»РµРґСѓСЋС‰РµР№ РІС‹РґР°С‡Рё
            window.selectedVipUserId = user.id;
        }

    } catch (error) {
        console.error('РћС€РёР±РєР° РїРѕРёСЃРєР° РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', error);
        showNotification('вќЊ РћС€РёР±РєР° РїРѕРёСЃРєР° РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ', 'error', 3000);
    }
};

// РџРѕРґС‚РІРµСЂР¶РґРµРЅРёРµ РІС‹РґР°С‡Рё VIP Р°РґРјРёРЅРёСЃС‚СЂР°С‚РѕСЂРѕРј
window.confirmGiveVipByAdmin = async function() {
    const password = document.getElementById('vipAdminPasswordInput').value;
    const userId = window.selectedVipUserId;

    if (!password) {
        showNotification('вќЊ Р’РІРµРґРёС‚Рµ VIP РїР°СЂРѕР»СЊ', 'error', 3000);
        return;
    }

    if (!userId) {
        showNotification('вќЊ РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ РІС‹Р±СЂР°РЅ', 'error', 3000);
        return;
    }

    try {
        // РџРѕР»СѓС‡Р°РµРј С‚РµРєСѓС‰РёР№ VIP РїР°СЂРѕР»СЊ РёР· localStorage
        let currentVipPassword = localStorage.getItem('vip_password') || 'VIP2026KEROS';

        // РџСЂРѕРІРµСЂСЏРµРј VIP РїР°СЂРѕР»СЊ
        if (password !== currentVipPassword) {
            showNotification('вќЊ РќРµРІРµСЂРЅС‹Р№ VIP РїР°СЂРѕР»СЊ! Р”РѕСЃС‚СѓРї Р·Р°РїСЂРµС‰РµРЅ.', 'error', 3000);
            return;
        }

        // Р’С‹РґР°РµРј VIP СЃС‚Р°С‚СѓСЃ
        const { error } = await supabase
            .from('profiles')
            .update({
                is_vip: true,
                role: 'vip',
                vip_expires_at: null // Р‘РµСЃСЃСЂРѕС‡РЅС‹Р№ VIP
            })
            .eq('id', userId);

        if (error) throw error;

        showNotification('вњ… VIP СЃС‚Р°С‚СѓСЃ СѓСЃРїРµС€РЅРѕ РІС‹РґР°РЅ!', 'success', 3000);
        
        // Р—Р°РєСЂС‹РІР°РµРј РјРѕРґР°Р»СЊРЅРѕРµ РѕРєРЅРѕ
        const modal = document.querySelector('.vip-give-modal');
        if (modal) modal.remove();

        // РћР±РЅРѕРІР»СЏРµРј СЃРїРёСЃРѕРє РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№
        if (typeof showVipUsersList === 'function') {
            showVipUsersList();
        }

        // Р›РѕРіРёСЂСѓРµРј РІ Р°СѓРґРёС‚
        console.log(`вњ… VIP РІС‹РґР°РЅ РїРѕР»СЊР·РѕРІР°С‚РµР»СЋ ID: ${userId}`);

    } catch (error) {
        console.error('РћС€РёР±РєР° РІС‹РґР°С‡Рё VIP:', error);
        showNotification('вќЊ РћС€РёР±РєР° РІС‹РґР°С‡Рё VIP СЃС‚Р°С‚СѓСЃР°', 'error', 3000);
    }
};

