// Р¤СѓРЅРєС†РёСЏ РїРѕРґС‚РІРµСЂР¶РґРµРЅРёСЏ СЃРјРµРЅС‹ СЂРѕР»Рё РІР»Р°РґРµР»СЊС†Р°
window.confirmOwnerRoleChange = async function(userId, newRole, oldRole) {
    const code = document.getElementById('ownerCodeInput').value;
    
    if (!code) {
        showNotification('вќЊ Р’РІРµРґРёС‚Рµ РєРѕРґ РґРѕСЃС‚СѓРїР°', 'error', 3000);
        return;
    }
    
    // РџРѕР»СѓС‡Р°РµРј С‚РµРєСѓС‰РёР№ РєРѕРґ РІР»Р°РґРµР»СЊС†Р° РёР· Р±Р°Р·С‹ РґпїЅпїЅРЅРЅС‹С…
    let currentOwnerCode = 'KEROS1980';
    
    try {
        const { data: ownerSettings } = await window.supabase
            .from('security_settings')
            .select('owner_code')
            .eq('id', 'owner_code')
            .single();
            
        if (ownerSettings?.owner_code) {
            currentOwnerCode = ownerSettings.owner_code;
        }
    } catch (error) {
        console.log('рџ”„ [confirmOwnerRoleChange] РСЃРїРѕпїЅпїЅСЊР·СѓРµРј РєРѕРґ РІР»Р°РґРµР»СЊС†Р° РїРѕ СѓРјРѕР»С‡Р°РЅРёСЋ РґР»СЏ РїСЂРѕРІРµСЂРєРё');
    }
    
    if (code !== currentOwnerCode) {
        showNotification('вќЊ РќРµРІРµСЂРЅС‹Р№ РєРѕРґ! Р”РѕСЃС‚СѓРї Р·Р°РїСЂРµС‰РµРЅ.', 'error', 3000);
        return;
    }
    
    // Р—Р°РєСЂС‹РІР°РµРј РјРѕРґР°Р»СЊРЅРѕРµ РѕРєРЅРѕ
    document.querySelector('.owner-modal')?.remove();
    
    // РџСЂРѕРґРѕР»Р¶Р°РµРј СЃ РёР·РјРµРЅРµРЅРёРµРј СЂРѕР»Рё
    proceedWithRoleChange(userId, newRole, oldRole);
};

// Р¤СѓРЅРєС†РёСЏ РѕС‚РјРµРЅС‹ СЃРјРµРЅС‹ СЂРѕР»Рё
