// Функция продолжения смены роли
window.proceedWithRoleChange = async function(userId, newRole, oldRole) {
    try {
        // 🔧 ИСПРАВЛЕНИЕ: Если новая роль не 'vip', сбрасываем VIP статус
        const updateData = { 
            role: newRole, 
            updated_at: new Date().toISOString() 
        };
        
        // Сбрасываем VIP статус если роль меняется на не-VIP
        if (newRole !== 'vip') {
            updateData.is_vip = false;
            updateData.vip_expires_at = null;
            console.log(`🔧 [ROLE_CHANGE] Сбрасываем VIP статус для пользователя ${userId} (новая роль: ${newRole})`);
        }
        
        const { error } = await window.supabase
            .from('profiles')
            .update(updateData)
            .eq('id', userId);

        if (error) throw error;

        showNotification(`✅ Роль пользователя успешно изменена на ${newRole}`, 'success', 3000);
        
        // 🔧 ИСПРАВЛЕНИЕ: Отправляем уведомление об изменении VIP статуса
        if (newRole !== 'vip' && oldRole === 'vip') {
            showNotification('⚠️ VIP статус также был сброшен', 'warning', 3000);
        }
        
        loadUsersList();

        // Обновляем статистику после изменения роли
        setTimeout(() => {
            refreshAllStats();
        }, 500);

    } catch (error) {
        console.error('❌ Ошибка изменения роли:', error);
        showNotification('❌ Ошибка при изменении роли: ' + error.message, 'error', 3000);
    }
};

