function updateStatisticsCountersAlternative(stats) {
    const counters = [
        { id: 'total-users-count', value: stats.total },
        { id: 'vip-users-count', value: stats.vip },
        { id: 'banned-users-count', value: stats.banned },
        { id: 'admin-users-count', value: stats.admin },
        { id: 'moderator-users-count', value: stats.moderator },
        { id: 'new-users-count', value: stats.new },
        { id: 'active-users-count', value: stats.active }
    ];
    
    counters.forEach(counter => {
        const element = document.getElementById(counter.id);
        if (element) {
            element.textContent = counter.value.toLocaleString();
            console.log(`вњ… ${counter.id}: ${counter.value}`);
        } else {
            console.log(`вќЊ Р­Р»РµРјРµРЅС‚ ${counter.id} РЅРµ РЅР°Р№РґРµРЅ`);
        }
    });
    
    // РћР±РЅРѕРІР»СЏРµРј РІСЂРµРјСЏ РїРѕСЃР»РµРґРЅРµРіРѕ РѕР±РЅРѕРІР»РµРЅРёСЏ
    const updateTimeElement = document.getElementById('statistics-update-time');
    if (updateTimeElement) {
        updateTimeElement.textContent = new Date().toLocaleTimeString('ru-RU');
    }
    
    console.log('вњ… РЎС‚Р°С‚РёСЃС‚РёРєР° РѕР±РЅРѕРІР»РµРЅР°');
}

