function startUserActivityTracking() {
    if (userActivityInterval) {
        clearInterval(userActivityInterval);
    }
    
    console.log('рџ”„ Р—Р°РїСѓС‰РµРЅРѕ РѕС‚СЃР»РµР¶РёРІР°РЅРёРµ Р°РєС‚РёРІРЅРѕСЃС‚Рё РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ...');
    
    const activityEvents = [
        'mousedown', 'mousemove', 'keypress', 'scroll', 
        'click', 'touchstart', 'touchmove', 'focus'
    ];
    
    activityEvents.forEach(event => {
        document.addEventListener(event, updateUserActivity, true);
    });
    
    userActivityInterval = setInterval(() => {
        updateUserActivityInDatabase();
    }, 30000); // 30 СЃРµРєСѓРЅРґ РІРјРµСЃС‚Рѕ 2 РјРёРЅСѓС‚
    
    updateUserActivityInDatabase();
}

function updateUserActivity() {
    lastActivityTime = new Date();
    // console.log('рџ‘† Р—Р°С„РёРєСЃРёСЂРѕРІР°РЅР° Р°РєС‚РёРІРЅРѕСЃС‚СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ:', lastActivityTime.toLocaleTimeString('ru-RU'));
}

async function updateUserActivityInDatabase() {
    try {
        const { data: { user }, error: authError } = await window.supabase.auth.getUser();
        
        if (authError || !user) {
            console.log('рџ‘¤ РџРѕР»СЊР·РѕРІР°С‚РµР»СЊ РЅРµ Р°РІС‚РѕСЂРёР·РѕРІР°РЅ, РїСЂРѕРїСѓСЃРєР°РµРј РѕР±РЅРѕРІР»РµРЅРёРµ Р°РєС‚РёРІРЅРѕСЃС‚Рё');
            return;
        }
        
        const currentTime = new Date().toISOString();
        const { error: updateError } = await window.supabase
            .from('profiles')
            .update({ 
                updated_at: currentTime
            })
            .eq('id', user.id);
            
        if (updateError) {
            console.warn('вљ пёЏ РћС€РёР±РєР° РѕР±РЅРѕРІР»РµРЅРёСЏ Р°РєС‚РёРІРЅРѕСЃС‚Рё:', updateError);
        } else {
            // console.log('вњ… РђРєС‚РёРІРЅРѕСЃС‚СЊ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РѕР±РЅРѕРІР»РµРЅР° РІ Р±Р°Р·Рµ');
        }
        
    } catch (error) {
        console.error('вќЊ РћС€РёР±РєР° РїСЂРё РѕР±РЅРѕРІР»РµРЅРёРё Р°РєС‚РёРІРЅРѕСЃС‚Рё:', error);
    }
}

function stopUserActivityTracking() {
    if (userActivityInterval) {
        clearInterval(userActivityInterval);
        userActivityInterval = null;
    }
    
    const activityEvents = [
        'mousedown', 'mousemove', 'keypress', 'scroll', 
        'click', 'touchstart', 'touchmove', 'focus'
    ];
    
    activityEvents.forEach(event => {
        document.removeEventListener(event, updateUserActivity, true);
    });
    
    console.log('вЏ№пёЏ РћС‚СЃР»РµР¶РёРІР°РЅРёРµ Р°РєС‚РёРІРЅРѕСЃС‚Рё РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РѕСЃС‚Р°РЅРѕРІР»РµРЅРѕ');
}

