/**
 * РџРѕРєР°Р·С‹РІР°РµС‚ РґРµС‚Р°Р»СЊРЅСѓСЋ РёРЅС„РѕСЂРјР°С†РёСЋ Рѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏС… РїРѕ РєР°С‚РµРіРѕСЂРёСЏРј
 */
async function showUserCategoryDetails(category) {
    try {
        console.log(`рџ”Ќ Р—Р°РіСЂСѓР·РєР° РґРµС‚Р°Р»СЊРЅРѕР№ РёРЅС„РѕСЂРјР°С†РёРё РїРѕ РєР°С‚РµРіРѕСЂРёРё: ${category}`);
        showNotification(`рџ”Ќ Р—Р°РіСЂСѓР·РєР° РёРЅС„РѕСЂРјР°С†РёРё...`, 'info', 2000);
        
        // РџРѕР»СѓС‡Р°РµРј РІСЃРµС… РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№
        const { data: allUsers, error: allError } = await supabase
            .from('profiles')
            .select('*');
            
        if (allError) throw allError;
        
        const now = new Date(); // РўРµРєСѓС‰РµРµ РІСЂРµРјСЏ
        
        // Р¤РёР»СЊС‚СЂСѓРµРј РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ РїРѕ РєР°С‚РµРіРѕСЂРёРё
        let filteredUsers = [];
        let categoryTitle = '';
        let categoryColor = '';
        
        switch(category) {
            case 'total':
                filteredUsers = allUsers;
                categoryTitle = 'рџ‘Ґ Р’СЃРµ РїРѕР»СЊР·РѕРІР°С‚РµР»Рё';
                categoryColor = '#2196F3';
                break;
                        case 'vip':
                filteredUsers = allUsers.filter(u => u.role === 'vip' || u.is_vip);
                categoryTitle = 'рџ’Ћ VIP РїРѕР»СЊР·РѕРІР°С‚РµР»Рё';
                categoryColor = '#ffd700';
                break;
            case 'banned':
                filteredUsers = allUsers.filter(u => u.is_banned);
                categoryTitle = 'рџљ« Р—Р°Р±Р»РѕРєРёСЂРѕРІР°РЅРЅС‹Рµ РїРѕР»СЊР·РѕРІР°С‚РµР»Рё';
                categoryColor = '#f44336';
                break;
            case 'admin':
                filteredUsers = allUsers.filter(u => ['admin', 'admin_senior', 'owner'].includes(u.role));
                categoryTitle = 'вљЎ РђРґРјРёРЅРёСЃС‚СЂР°С‚РѕСЂС‹';
                categoryColor = '#9c27b0';
                break;
            case 'moderator':
                filteredUsers = allUsers.filter(u => ['moderator', 'moderator_senior'].includes(u.role));
                categoryTitle = 'рџ›ЎпёЏ РњРѕРґРµСЂР°С‚РѕСЂС‹';
                categoryColor = '#ff9800';
                break;
            case 'new':
                const sevenDaysAgo = new Date();
                sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
                filteredUsers = allUsers.filter(u => {
                    const createdAt = new Date(u.created_at);
                    return createdAt > sevenDaysAgo;
                });
                categoryTitle = 'рџ†• РќРѕРІС‹Рµ РїРѕР»СЊР·РѕРІР°С‚РµР»Рё (7 РґРЅРµР№)';
                categoryColor = '#00bcd4';
                break;
            case 'active':
                const thirtyDaysAgo = new Date();
                thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
                filteredUsers = allUsers.filter(u => {
                    const updatedTime = new Date(u.updated_at || u.created_at);
                    return updatedTime > thirtyDaysAgo;
                });
                categoryTitle = 'рџ”Ґ РђРєС‚РёРІРЅС‹Рµ РїРѕР»СЊР·РѕРІР°С‚РµР»Рё (30 РґРЅРµР№)';
                categoryColor = '#ff5722';
                break;
        }
        
        // РџРѕР»СѓС‡Р°РµРј РґРѕРїРѕР»РЅРёС‚РµР»СЊРЅСѓСЋ СЃС‚Р°С‚РёСЃС‚РёРєСѓ
        const stats = await getCategoryStats(filteredUsers, category);
        
        // РџРѕРєР°Р·С‹РІР°РµРј РјРѕРґР°Р»СЊРЅРѕРµ РѕРєРЅРѕ СЃ РґРµС‚Р°Р»СЊРЅРѕР№ РёРЅС„РѕСЂРјР°С†РёРµР№
        showUserListModal(filteredUsers, categoryTitle, categoryColor, stats);
        
    } catch (error) {
        console.error('вќЊ РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё РґРµС‚Р°Р»СЊРЅРѕР№ РёРЅС„РѕСЂРјР°С†РёРё:', error);
        showNotification('вќЊ РћС€РёР±РєР° Р·Р°РіСЂСѓР·РєРё РёРЅС„РѕСЂРјР°С†РёРё', 'error');
    }
}

/**
 * РџРѕР»СѓС‡Р°РµС‚ СЃС‚Р°С‚РёСЃС‚РёРєСѓ РїРѕ РєР°С‚РµРіРѕСЂРёРё РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№ (РќРћР’РђРЇ Р’Р•Р РЎРРЇ)
 */
async function getCategoryStats(users, category) {
    let vipCount = 0;
    
    users.forEach(user => {
        // VIP СЃС‚Р°С‚СѓСЃ
        if (user.is_vip || user.role === 'vip') {
            vipCount++;
        }
    });
    
    const stats = {
        total: users.length,
        vip: vipCount,
        banned: users.filter(u => u.is_banned).length,
        commentBanned: 0,
        totalDownloads: 0,
        avgDownloads: 0
    };
    
    // Получаем информацию о блокировках комментариев
    if (users.length > 0) {
        const userIds = users.map(u => u.id).filter(id => id);
        if (userIds.length > 0) {
            const now = new Date().toISOString();

            // Запрос 1: Бессрочные (ends_at is null)
            let commentBans = null;
            let commentBansError = null;
            try {
                const { data: nullCommentBans, error: nullBansError } = await supabase
                    .from('comment_bans')
                    .select('user_id')
                    .filter('ends_at', 'is', null)
                    .in('user_id', userIds);

                if (!nullBansError && nullCommentBans && nullCommentBans.length > 0) {
                    commentBans = nullCommentBans;
                }
                commentBansError = nullBansError;
            } catch (e) {
                console.warn('Ошибка при проверке бессрочных блокировок комментариев:', e);
                commentBansError = e;
            }

            if (!commentBans && !commentBansError) {
                // Запрос 2: Активные (ends_at > now)
                try {
                    const { data: activeCommentBans, error: activeBansError } = await supabase
                        .from('comment_bans')
                        .select('user_id')
                        .filter('ends_at', 'gt', now)
                        .in('user_id', userIds);

                    if (!activeBansError && activeCommentBans) {
                        commentBans = activeCommentBans;
                    }
                } catch (e) {
                    console.warn('Ошибка при проверке активных блокировок комментариев:', e);
                }
            }

            if (commentBans) {
                stats.commentBanned = commentBans.length;
            }
        }
    }
    
    stats.totalDownloads = users.reduce((sum, user) => sum + (user.downloads_count || 0), 0);
    stats.avgDownloads = users.length > 0 ? Math.round(stats.totalDownloads / users.length) : 0;
    
    return stats;
}

