window.downloadMod = async function(modId) {
    try {
        console.log('рџ”ђ [GLOBAL DOWNLOAD] Р—Р°РїСЂРѕСЃ РЅР° СЃРєР°С‡РёРІР°РЅРёРµ РјРѕРґР°:', modId);
        
        // РџСЂРѕРІРµСЂСЏРµРј Р°РІС‚РѕСЂРёР·Р°С†РёСЋ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ
        const { data: { user } } = await window.supabase.auth.getUser();

        if (!user) {
            showNotification('РќРµРѕР±С…РѕРґРёРјРѕ РІРѕР№С‚Рё РІ СЃРёСЃС‚РµРјСѓ РґР»СЏ СЃРєР°С‡РёРІР°РЅРёСЏ РјРѕРґРѕРІ', 'error');
            showLoginModal();
            return;
        }

        // РСЃРїРѕР»СЊР·СѓРµРј Р·Р°С‰РёС‰РµРЅРЅСѓСЋ СЃРёСЃС‚РµРјСѓ СЃРєР°С‡РёРІР°РЅРёСЏ РµСЃР»Рё РґРѕСЃС‚СѓРїРЅР°
        if (window.secureDownloadManager) {
            console.log('рџ”ђ [GLOBAL DOWNLOAD] РСЃРїРѕР»СЊР·СѓРµРј Р·Р°С‰РёС‰РµРЅРЅРѕРµ СЃРєР°С‡РёРІР°РЅРёРµ...');
            await window.secureDownloadManager.downloadModSecure(modId);
            return;
        }

        // Fallback Рє СЃС‚Р°СЂРѕРјСѓ РјРµС‚РѕРґСѓ
        console.log('вљ пёЏ [GLOBAL DOWNLOAD] Р—Р°С‰РёС‰РµРЅРЅРѕРµ СЃРєР°С‡РёРІР°РЅРёРµ РЅРµРґРѕСЃС‚СѓРїРЅРѕ, РёСЃРїРѕР»СЊР·СѓРµРј СЃС‚Р°СЂС‹Р№ РјРµС‚РѕРґ...');
        
        // РџСЂРѕРІРµСЂСЏРµРј, РЅРµ Р·Р°Р±Р°РЅРµРЅ Р»Рё РїРѕР»СЊР·РѕРІР°С‚РµР»СЊ
        const { data: profile, error: profileError } = await supabase
            .from('profiles')
            .select('is_banned, role, is_vip, vip_expires_at')
            .eq('id', user.id)
            .single();

        if (profileError) throw profileError;

        // РџСЂРѕРІРµСЂСЏРµРј, СЏРІР»СЏРµС‚СЃСЏ Р»Рё РјРѕРґ РїСЂРёРІР°С‚РЅС‹Рј
        const isPrivateMod = mod.is_private || false;

        if (isPrivateMod) {
            console.log('рџ’Ћ [GLOBAL DOWNLOAD] VIP РјРѕРґ, РїСЂРѕРІРµСЂСЏРµРј РґРѕСЃС‚СѓРї...');
            
            // РџСЂРѕРІРµСЂСЏРµРј РїСЂР°РІР° РґРѕСЃС‚СѓРїР°
            const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
            const hasRoleAccess = profile && vipRoles.includes(profile.role);
            const hasVipFlag = profile?.is_vip === true;
            const isNotExpired = !profile?.vip_expires_at || new Date(profile.vip_expires_at) > new Date();
            const hasVipAccess = (hasRoleAccess || hasVipFlag) && isNotExpired;

            console.log('рџ”Ќ [GLOBAL DOWNLOAD] VIP РїСЂРѕРІРµСЂРєР°:', {
                hasRoleAccess,
                hasVipFlag,
                isNotExpired,
                hasVipAccess,
                role: profile?.role,
                is_vip: profile?.is_vip,
                vip_expires_at: profile?.vip_expires_at
            });

            if (!hasVipAccess) {
                alert('вќЊ Р­С‚РѕС‚ РјРѕРґ РґРѕСЃС‚СѓРїРµРЅ С‚РѕР»СЊРєРѕ РґР»СЏ VIP РїРѕР»СЊР·РѕРІР°С‚РµР»РµР№!\n\nРџРѕР»СѓС‡РёС‚Рµ VIP СЃС‚Р°С‚СѓСЃ РґР»СЏ РґРѕСЃС‚СѓРїР° Рє РїСЂпїЅпїЅРІР°С‚РЅС‹Рј РјРѕРґР°Рј.');
                return;
            }
        }

        // РЈРІРµР»РёС‡РёРІР°РµРј СЃС‡РµС‚С‡РёРє СЃРєР°С‡РёРІР°РЅРёР№
        await supabase
            .from('mods')
            .update({ download_count: (mod.download_count || 0) + 1 })
            .eq('id', modId);

        // РЎРѕР·РґР°РµРј СЃСЃС‹Р»РєСѓ РґР»СЏ СЃРєР°С‡РёРІР°РЅРёСЏ
        const downloadLink = document.createElement('a');
        downloadLink.href = mod.download_url;
        downloadLink.target = '_blank';
        downloadLink.rel = 'noopener noreferrer';
        downloadLink.download = mod.name || 'mod.zip';
        
        // Р”РѕР±Р°РІР»СЏРµРј РЅР° СЃС‚СЂР°РЅРёС†Сѓ Рё РєР»РёРєР°РµРј
        document.body.appendChild(downloadLink);
        downloadLink.click();
        document.body.removeChild(downloadLink);

        showNotification(`вњ… РњРѕРґ "${mod.name}" СѓСЃРїРµС€РЅРѕ СЃРєР°С‡РёРІР°РµС‚СЃСЏ!`, 'success');

    } catch (error) {
        console.error('вќЊ [GLOBAL DOWNLOAD] РћС€РёР±РєР° СЃРєР°С‡РёРІР°РЅРёСЏ:', error);
        showNotification('вќЊ РћС€РёР±РєР° РїСЂРё СЃРєР°С‡РёРІР°РЅРёРё РјРѕРґР°: ' + error.message, 'error');
    }
};

