        document.body.appendChild(modal);

        // Р—Р°РіСЂСѓР¶Р°РµРј РєРѕРјРјРµРЅС‚Р°СЂРёРё РїРѕСЃР»Рµ СЃРѕР·РґР°РЅРёСЏ РјРѕРґР°Р»СЊРЅРѕРіРѕ РѕРєРЅР°
        const commentsContainer = document.getElementById(`comments-list-${modId}`);
